SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An ideal transformer has a primary voltage of 240 V and delivers 12 V to a load that draws 2 A. The primary current is:", "explanation": "For an ideal transformer, P_p = P_s. So V_p × I_p = V_s × I_s. I_p = V_s × I_s / V_p = 12 × 2 / 240 = 24/240 = 0.1 A.", "correct_answer": "A", "concept_tags": ["transformer", "power-conservation", "numerical-problem"], "payload": {"question_id": "cuet-phy-ac-circuits-34", "subtopic": "transformer", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "0.1 A", "is_correct": true}, {"key": "B", "value": "0.5 A", "is_correct": false}, {"key": "C", "value": "2 A", "is_correct": false}, {"key": "D", "value": "40 A", "is_correct": false}], "elimination_hints": ["Power conservation: V_p × I_p = V_s × I_s = 12 × 2 = 24 W.", "I_p = 24/240 = 0.1 A.", "Since this is a step-down transformer (240 V → 12 V), the primary current must be less than the secondary current."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Energy losses in a transformer can be reduced by:", "explanation": "Major transformer losses include: (1) Eddy current losses — reduced by using laminated iron core, (2) Hysteresis losses — reduced by using soft iron (low coercivity), (3) Copper losses (I²R) — reduced by using thick copper wires, (4) Flux leakage — reduced by winding coils over each other.", "correct_answer": "D", "concept_tags": ["transformer", "energy-losses", "lamination"], "payload": {"question_id": "cuet-phy-ac-circuits-35", "subtopic": "transformer losses", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "Using a solid iron core", "is_correct": false}, {"key": "B", "value": "Using thin wires for windings", "is_correct": false}, {"key": "C", "value": "Keeping primary and secondary coils far apart", "is_correct": false}, {"key": "D", "value": "Using a laminated soft iron core with thick copper windings", "is_correct": true}], "elimination_hints": ["Solid iron cores have large eddy currents — lamination reduces them.", "Thin wires have high resistance, increasing I²R (copper) losses.", "Keeping coils far apart increases flux leakage — they should be close together."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A series LCR circuit has R = 20 Ω, L = 0.2 H, C = 50 μF and is connected to a 220 V, 50 Hz source. The current in the circuit is approximately:", "explanation": "X_L = 2πfL = 2π × 50 × 0.2 = 20π ≈ 62.8 Ω. X_C = 1/(2πfC) = 1/(2π × 50 × 50 × 10⁻⁶) = 1/(5π × 10⁻³) = 200/π ≈ 63.7 Ω. X_L − X_C ≈ 62.8 − 63.7 = −0.9 Ω. Z = √(20² + 0.81) ≈ √(400.81) ≈ 20.02 Ω. I = V/Z = 220/20.02 ≈ 11 A.", "correct_answer": "C", "concept_tags": ["LCR-circuit", "impedance", "numerical-problem"], "payload": {"question_id": "cuet-phy-ac-circuits-36", "subtopic": "series LCR circuit", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "2.5 A", "is_correct": false}, {"key": "B", "value": "5 A", "is_correct": false}, {"key": "C", "value": "11 A", "is_correct": true}, {"key": "D", "value": "22 A", "is_correct": false}], "elimination_hints": ["X_L ≈ X_C ≈ 63 Ω, so they nearly cancel — the circuit is near resonance.", "Near resonance, Z ≈ R = 20 Ω, so I ≈ 220/20 = 11 A.", "22 A would imply Z ≈ 10 Ω, which is less than R alone — impossible."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a series LCR circuit, if X_L > X_C, the circuit is:", "explanation": "When X_L > X_C, the net reactance is inductive (positive). The current lags behind the voltage. The phase angle φ = tan⁻¹[(X_L − X_C)/R] is positive, meaning the circuit behaves inductively.", "correct_answer": "A", "concept_tags": ["LCR-circuit", "inductive-behavior", "phase-angle"], "payload": {"question_id": "cuet-phy-ac-circuits-37", "subtopic": "series LCR circuit", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "Inductive (current lags voltage)", "is_correct": true}, {"key": "B", "value": "Capacitive (current leads voltage)", "is_correct": false}, {"key": "C", "value": "Resistive (current in phase with voltage)", "is_correct": false}, {"key": "D", "value": "At resonance", "is_correct": false}], "elimination_hints": ["X_L > X_C means inductive reactance dominates — the circuit behaves like an inductor.", "Capacitive behavior requires X_C > X_L.", "At resonance, X_L = X_C exactly."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A transformer cannot work with DC because:", "explanation": "A transformer requires changing magnetic flux to induce EMF in the secondary (Faraday''s law). DC produces a constant current, hence a constant magnetic flux, so dΦ/dt = 0 and no EMF is induced in the secondary. Additionally, DC can saturate the core.", "correct_answer": "B", "concept_tags": ["transformer", "DC-limitation", "flux-change"], "payload": {"question_id": "cuet-phy-ac-circuits-38", "subtopic": "transformer", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "DC produces too much current", "is_correct": false}, {"key": "B", "value": "DC produces a constant flux which does not induce EMF in the secondary", "is_correct": true}, {"key": "C", "value": "DC cannot flow through the primary coil", "is_correct": false}, {"key": "D", "value": "DC destroys the core material", "is_correct": false}], "elimination_hints": ["DC can certainly flow through the primary coil (it''s just a wire).", "The problem is not the amount of current but the lack of changing flux.", "Faraday''s law: ε = −dΦ/dt. If Φ is constant (DC), ε = 0 in the secondary."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In long-distance power transmission, electrical energy is transmitted at high voltage and low current because:", "explanation": "Power loss in transmission lines = I²R, where R is the line resistance. By using high voltage (via step-up transformer), the current is reduced for the same power (P = VI). Lower current means much less I²R power loss. At the receiving end, a step-down transformer reduces the voltage for consumer use.", "correct_answer": "D", "concept_tags": ["power-transmission", "high-voltage", "I²R-losses"], "payload": {"question_id": "cuet-phy-ac-circuits-39", "subtopic": "power transmission", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "High voltage is safer for transmission", "is_correct": false}, {"key": "B", "value": "High voltage reduces the cost of cables", "is_correct": false}, {"key": "C", "value": "Low current increases the power delivered", "is_correct": false}, {"key": "D", "value": "Low current reduces I²R transmission losses", "is_correct": true}], "elimination_hints": ["High voltage is actually more dangerous, not safer.", "Power delivered P = VI remains the same; only the losses change.", "Transmission losses depend on I²R — reducing I drastically reduces losses."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An AC source of 220 V, 50 Hz is connected to a series combination of a 10 Ω resistance and a capacitor of 100/(π) μF. The power dissipated in the circuit is:", "explanation": "X_C = 1/(2πfC) = 1/(2π × 50 × 100/(π) × 10⁻⁶) = 1/(2 × 50 × 100 × 10⁻⁶) = 1/(10⁻² ) = 100 Ω. Z = √(R² + X_C²) = √(100 + 10000) = √10100 ≈ 100.5 Ω. I_rms = 220/100.5 ≈ 2.19 A. Power = I²R = (2.19)² × 10 ≈ 48 W. Alternatively, P = V²R/Z² = 220² × 10/10100 ≈ 484000/10100 ≈ 48 W.", "correct_answer": "B", "concept_tags": ["RC-circuit", "power-dissipation", "numerical-problem"], "payload": {"question_id": "cuet-phy-ac-circuits-40", "subtopic": "power in AC circuits", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "24 W", "is_correct": false}, {"key": "B", "value": "48 W", "is_correct": true}, {"key": "C", "value": "484 W", "is_correct": false}, {"key": "D", "value": "4840 W", "is_correct": false}], "elimination_hints": ["X_C = 100 Ω (much larger than R = 10 Ω), so Z ≈ 100.5 Ω.", "484 W = V²/R — this ignores the capacitive reactance entirely.", "P = V²R/Z² = (220)² × 10 / (100.5)² ≈ 48 W."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In an LC oscillating circuit, the total energy is:", "explanation": "In an ideal LC circuit, energy oscillates between the inductor (magnetic energy ½LI²) and the capacitor (electric energy ½CV²). The total energy remains constant as there is no resistance to dissipate energy. At any instant, U_total = ½LI² + ½CV² = ½CV₀² = ½LI₀² = constant.", "correct_answer": "C", "concept_tags": ["LC-oscillation", "energy-conservation", "electromagnetic-oscillation"], "payload": {"question_id": "cuet-phy-ac-adv-01", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "Stored only in the inductor", "is_correct": false}, {"key": "B", "value": "Stored only in the capacitor", "is_correct": false}, {"key": "C", "value": "Constant and shared between L and C", "is_correct": true}, {"key": "D", "value": "Continuously dissipated as heat", "is_correct": false}], "elimination_hints": ["Energy is stored in the inductor only at the instant of maximum current.", "Energy is stored in the capacitor only at the instant of maximum charge.", "There is no resistance in an ideal LC circuit, so no heat is dissipated."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The frequency of oscillation in an ideal LC circuit with inductance L and capacitance C is:", "explanation": "The angular frequency of LC oscillation is ω = 1/√(LC), so the frequency f = ω/(2π) = 1/(2π√(LC)). This is analogous to SHM of a spring-mass system where ω = √(k/m).", "correct_answer": "B", "concept_tags": ["LC-oscillation", "frequency", "angular-frequency"], "payload": {"question_id": "cuet-phy-ac-adv-02", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "1/(2π)√(L/C)", "is_correct": false}, {"key": "B", "value": "1/(2π√(LC))", "is_correct": true}, {"key": "C", "value": "2π√(LC)", "is_correct": false}, {"key": "D", "value": "1/(2πLC)", "is_correct": false}], "elimination_hints": ["√(L/C) has dimensions of impedance, not frequency.", "2π√(LC) has dimensions of time (the time period T), not frequency.", "1/(2πLC) does not have the correct dimensions of frequency."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an LC circuit, the charge on the capacitor oscillates as q = q₀ cos(ωt). The current in the circuit is:", "explanation": "Current I = dq/dt = d(q₀ cos(ωt))/dt = −q₀ω sin(ωt). The magnitude of maximum current I₀ = q₀ω. The current leads the charge by π/2 (90°). When charge is maximum, current is zero and vice versa.", "correct_answer": "A", "concept_tags": ["LC-oscillation", "current", "differentiation", "phase"], "payload": {"question_id": "cuet-phy-ac-adv-03", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "−q₀ω sin(ωt)", "is_correct": true}, {"key": "B", "value": "q₀ω sin(ωt)", "is_correct": false}, {"key": "C", "value": "q₀ω cos(ωt)", "is_correct": false}, {"key": "D", "value": "−q₀ω cos(ωt)", "is_correct": false}], "elimination_hints": ["Current is the derivative of charge, not the same function.", "d(cos(ωt))/dt = −ω sin(ωt), so the negative sign is essential.", "cos differentiates to −sin, not to cos or +sin."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The LC oscillation is analogous to the mechanical oscillation of a spring-mass system. In this analogy, the inductance L corresponds to:", "explanation": "In the LC-SHM analogy: inductance L ↔ mass m, capacitance C ↔ 1/k (inverse of spring constant), charge q ↔ displacement x, current I ↔ velocity v, ½LI² ↔ ½mv² (kinetic energy), ½q²/C ↔ ½kx² (potential energy).", "correct_answer": "B", "concept_tags": ["LC-oscillation", "SHM-analogy", "inductance"], "payload": {"question_id": "cuet-phy-ac-adv-04", "subtopic": "LC oscillations — SHM analogy", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "Spring constant k", "is_correct": false}, {"key": "B", "value": "Mass m", "is_correct": true}, {"key": "C", "value": "Displacement x", "is_correct": false}, {"key": "D", "value": "Velocity v", "is_correct": false}], "elimination_hints": ["Spring constant k corresponds to 1/C, not L.", "Displacement x corresponds to charge q.", "L appears in ½LI² which is analogous to ½mv², so L ↔ m."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an LC oscillating circuit with inductance L = 0.5 H and capacitance C = 20 μF, the angular frequency of oscillation is:", "explanation": "ω = 1/√(LC) = 1/√(0.5 × 20 × 10⁻⁶) = 1/√(10⁻⁵) = 1/(10⁻²·⁵) = 10²·⁵ = √(10⁵) = √(100000) ≈ 316.2 rad/s. Rounding: ω = 100√10 ≈ 316 rad/s.", "correct_answer": "C", "concept_tags": ["LC-oscillation", "angular-frequency", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-05", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "100 rad/s", "is_correct": false}, {"key": "B", "value": "200 rad/s", "is_correct": false}, {"key": "C", "value": "100√10 rad/s", "is_correct": true}, {"key": "D", "value": "1000 rad/s", "is_correct": false}], "elimination_hints": ["LC = 0.5 × 20 × 10⁻⁶ = 10⁻⁵, so √(LC) = 10⁻²·⁵.", "1/10⁻²·⁵ = 10²·⁵ = √(10⁵) = 100√10 ≈ 316 rad/s.", "100 rad/s and 1000 rad/s are common traps from unit errors."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "When the current in an LC circuit is maximum, the energy stored in the inductor is:", "explanation": "When current is maximum (I = I₀), all energy is stored in the inductor as magnetic energy: U_L = ½LI₀². At this instant the capacitor is fully discharged (q = 0), so U_C = 0. The total energy equals ½LI₀².", "correct_answer": "D", "concept_tags": ["LC-oscillation", "magnetic-energy", "energy-transfer"], "payload": {"question_id": "cuet-phy-ac-adv-06", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "Zero", "is_correct": false}, {"key": "B", "value": "Half of the total energy", "is_correct": false}, {"key": "C", "value": "One-fourth of the total energy", "is_correct": false}, {"key": "D", "value": "Equal to the total energy", "is_correct": true}], "elimination_hints": ["Zero energy in the inductor occurs when current is zero, not maximum.", "Energy is equally shared when I = I₀/√2, not at maximum current.", "At maximum current, the capacitor is fully discharged — all energy is in L."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The power factor of a purely resistive AC circuit is:", "explanation": "Power factor = cos φ, where φ is the phase difference between voltage and current. In a purely resistive circuit, voltage and current are in phase (φ = 0°), so cos 0° = 1. Maximum power is dissipated.", "correct_answer": "A", "concept_tags": ["power-factor", "resistive-circuit", "phase-angle"], "payload": {"question_id": "cuet-phy-ac-adv-07", "subtopic": "power factor", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "1", "is_correct": true}, {"key": "B", "value": "0", "is_correct": false}, {"key": "C", "value": "0.5", "is_correct": false}, {"key": "D", "value": "∞", "is_correct": false}], "elimination_hints": ["Power factor = 0 for purely reactive (L or C) circuits, not resistive.", "cos φ always lies between 0 and 1; it cannot be ∞.", "In a purely resistive circuit, φ = 0° and cos 0° = 1."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The wattless component of current in an AC circuit is:", "explanation": "In an AC circuit, the current has two components: (1) I cos φ — the active or wattful component (in phase with voltage, responsible for power dissipation), and (2) I sin φ — the reactive or wattless component (90° out of phase with voltage, contributes zero average power).", "correct_answer": "B", "concept_tags": ["wattless-current", "reactive-component", "power-factor"], "payload": {"question_id": "cuet-phy-ac-adv-08", "subtopic": "wattless current", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "I cos φ", "is_correct": false}, {"key": "B", "value": "I sin φ", "is_correct": true}, {"key": "C", "value": "I tan φ", "is_correct": false}, {"key": "D", "value": "I/cos φ", "is_correct": false}], "elimination_hints": ["I cos φ is the wattful (active) component, not the wattless component.", "I tan φ and I/cos φ do not represent standard AC current components.", "The wattless component is perpendicular to voltage — it involves sin φ."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a purely inductive AC circuit, the wattless component of current is:", "explanation": "In a purely inductive circuit, the phase angle φ = 90° (current lags voltage by π/2). The wattless component = I sin φ = I sin 90° = I (the entire current). The active component = I cos 90° = 0. Hence no power is dissipated — all current is wattless.", "correct_answer": "C", "concept_tags": ["wattless-current", "inductive-circuit", "phase-angle"], "payload": {"question_id": "cuet-phy-ac-adv-09", "subtopic": "wattless current", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "Zero", "is_correct": false}, {"key": "B", "value": "I/√2", "is_correct": false}, {"key": "C", "value": "I (total current)", "is_correct": true}, {"key": "D", "value": "I/2", "is_correct": false}], "elimination_hints": ["Zero wattless current occurs in a purely resistive circuit (φ = 0).", "I/√2 would occur when φ = 45°, not 90°.", "For purely inductive circuit φ = 90°, so sin 90° = 1 → entire current is wattless."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An AC circuit has an impedance of 50 Ω and the voltage leads the current by 60°. The wattful and wattless components of a 4 A current are:", "explanation": "Wattful component = I cos φ = 4 × cos 60° = 4 × 0.5 = 2 A. Wattless component = I sin φ = 4 × sin 60° = 4 × (√3/2) = 2√3 A. The power dissipated = V_rms × I × cos φ = 50 × 4 × 4 × 0.5 = 400 W (or equivalently I²R where R = Z cos φ = 25 Ω).", "correct_answer": "B", "concept_tags": ["wattless-current", "wattful-current", "numerical", "impedance"], "payload": {"question_id": "cuet-phy-ac-adv-10", "subtopic": "wattless current", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "2√3 A and 2 A", "is_correct": false}, {"key": "B", "value": "2 A and 2√3 A", "is_correct": true}, {"key": "C", "value": "4 A and 0 A", "is_correct": false}, {"key": "D", "value": "0 A and 4 A", "is_correct": false}], "elimination_hints": ["Option A swaps the wattful and wattless values.", "4 A and 0 A would mean φ = 0° (purely resistive), but φ = 60°.", "cos 60° = 0.5, so wattful = 4 × 0.5 = 2 A; sin 60° = √3/2, so wattless = 2√3 A."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The power dissipated in a purely capacitive AC circuit is:", "explanation": "In a purely capacitive circuit, the phase angle φ = 90° (current leads voltage by π/2). Average power P = V_rms × I_rms × cos φ = V_rms × I_rms × cos 90° = 0. Energy is alternately stored in and returned from the capacitor''s electric field.", "correct_answer": "A", "concept_tags": ["power", "capacitive-circuit", "wattless"], "payload": {"question_id": "cuet-phy-ac-adv-11", "subtopic": "power in reactive circuits", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "Zero", "is_correct": true}, {"key": "B", "value": "V_rms × I_rms", "is_correct": false}, {"key": "C", "value": "½ V_rms × I_rms", "is_correct": false}, {"key": "D", "value": "V_rms²/X_C", "is_correct": false}], "elimination_hints": ["V_rms × I_rms is the apparent power, not the true (real) power.", "V_rms²/X_C gives the reactive power (VAR), not the real power (W).", "cos 90° = 0, so no real power is dissipated in a purely capacitive circuit."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The quality factor (Q-factor) of a series LCR circuit at resonance is given by:", "explanation": "Q-factor = ω₀L/R = 1/(ω₀CR) = (1/R)√(L/C). It measures the sharpness of resonance — a higher Q means a narrower resonance peak. Q also equals the ratio of voltage across L (or C) to the applied voltage at resonance.", "correct_answer": "D", "concept_tags": ["Q-factor", "resonance", "LCR-circuit", "sharpness"], "payload": {"question_id": "cuet-phy-ac-adv-12", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "R/(ω₀L)", "is_correct": false}, {"key": "B", "value": "ω₀CR", "is_correct": false}, {"key": "C", "value": "R√(L/C)", "is_correct": false}, {"key": "D", "value": "(1/R)√(L/C)", "is_correct": true}], "elimination_hints": ["R/(ω₀L) is 1/Q, the inverse of the quality factor.", "ω₀CR is also 1/Q — inverting the correct formula.", "Q = ω₀L/R = (1/R)√(L/C). Higher L/C ratio and lower R give higher Q."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A series LCR circuit has L = 10 mH, C = 1 μF, and R = 10 Ω at resonance. The Q-factor of the circuit is:", "explanation": "Q = (1/R)√(L/C) = (1/10)√(10 × 10⁻³/(1 × 10⁻⁶)) = (1/10)√(10⁴) = (1/10) × 100 = 10. Alternatively, ω₀ = 1/√(LC) = 1/√(10⁻⁸) = 10⁴ rad/s, and Q = ω₀L/R = 10⁴ × 10⁻² / 10 = 10.", "correct_answer": "C", "concept_tags": ["Q-factor", "numerical", "LCR-circuit"], "payload": {"question_id": "cuet-phy-ac-adv-13", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "1", "is_correct": false}, {"key": "B", "value": "5", "is_correct": false}, {"key": "C", "value": "10", "is_correct": true}, {"key": "D", "value": "100", "is_correct": false}], "elimination_hints": ["√(L/C) = √(10⁻²/10⁻⁶) = √(10⁴) = 100.", "Q = 100/R = 100/10 = 10.", "100 would be the voltage magnification factor times R, not Q itself."]}}]'::jsonb, 'deploy-2026-03-05-b06');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The bandwidth (Δω) of a series LCR resonant circuit is given by:", "explanation": "Bandwidth Δω = R/L. It is the range of angular frequencies around resonance for which the power is at least half the maximum power (half-power points). A higher Q-factor means smaller bandwidth: Δω = ω₀/Q = R/L.", "correct_answer": "A", "concept_tags": ["bandwidth", "resonance", "LCR-circuit", "half-power"], "payload": {"question_id": "cuet-phy-ac-adv-14", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "R/L", "is_correct": true}, {"key": "B", "value": "L/R", "is_correct": false}, {"key": "C", "value": "1/√(LC)", "is_correct": false}, {"key": "D", "value": "R/C", "is_correct": false}], "elimination_hints": ["L/R is the time constant of an LR circuit, not bandwidth.", "1/√(LC) is the resonant frequency ω₀, not the bandwidth.", "Bandwidth = ω₀/Q = (1/√(LC))/(ω₀L/R) = R/L."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a series LCR circuit, L = 0.1 H, C = 10 μF, and R = 20 Ω. The bandwidth and Q-factor of the circuit are:", "explanation": "Bandwidth Δω = R/L = 20/0.1 = 200 rad/s. Resonant frequency ω₀ = 1/√(LC) = 1/√(0.1 × 10 × 10⁻⁶) = 1/√(10⁻⁶) = 1000 rad/s. Q = ω₀/Δω = 1000/200 = 5. Alternatively, Q = ω₀L/R = 1000 × 0.1/20 = 5.", "correct_answer": "B", "concept_tags": ["bandwidth", "Q-factor", "numerical", "resonance"], "payload": {"question_id": "cuet-phy-ac-adv-15", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "100 rad/s and 10", "is_correct": false}, {"key": "B", "value": "200 rad/s and 5", "is_correct": true}, {"key": "C", "value": "200 rad/s and 10", "is_correct": false}, {"key": "D", "value": "500 rad/s and 2", "is_correct": false}], "elimination_hints": ["Δω = R/L = 20/0.1 = 200, so options with 100 or 500 are wrong.", "Q = ω₀L/R = 1000 × 0.1 / 20 = 5.", "Options with Q = 10 use ω₀ = 1000 but divide by R = 100 (wrong R)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "At resonance in a series LCR circuit, the voltage across the capacitor is Q times the applied voltage. If Q = 20 and the applied RMS voltage is 10 V, the voltage across the capacitor is:", "explanation": "At resonance, V_C = Q × V_applied = 20 × 10 = 200 V. This is because at resonance, X_L = X_C, and the current I = V/R. Voltage across C = IX_C = (V/R)(ω₀L) = V × (ω₀L/R) = VQ. The voltage across L also equals 200 V, and V_L and V_C cancel each other.", "correct_answer": "D", "concept_tags": ["Q-factor", "voltage-magnification", "resonance", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-16", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "10 V", "is_correct": false}, {"key": "B", "value": "20 V", "is_correct": false}, {"key": "C", "value": "100 V", "is_correct": false}, {"key": "D", "value": "200 V", "is_correct": true}], "elimination_hints": ["10 V is the applied voltage, not the amplified voltage across C.", "Q-factor acts as a voltage amplification factor at resonance.", "V_C = Q × V = 20 × 10 = 200 V."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The average power consumed in an AC circuit is given by:", "explanation": "Average power P = V_rms × I_rms × cos φ, where cos φ is the power factor. This is also written as P = I²_rms × R. The term V_rms × I_rms is the apparent power, and cos φ converts it to the actual (real) power dissipated.", "correct_answer": "C", "concept_tags": ["average-power", "power-factor", "real-power"], "payload": {"question_id": "cuet-phy-ac-adv-17", "subtopic": "power in AC circuits", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "V_rms × I_rms", "is_correct": false}, {"key": "B", "value": "V_rms × I_rms × sin φ", "is_correct": false}, {"key": "C", "value": "V_rms × I_rms × cos φ", "is_correct": true}, {"key": "D", "value": "V_rms × I_rms × tan φ", "is_correct": false}], "elimination_hints": ["V_rms × I_rms is the apparent power (VA), not the real power (W).", "sin φ gives the reactive component, not the power-dissipating component.", "Only the in-phase component (cos φ) contributes to real power dissipation."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The power factor of a series LCR circuit at resonance is:", "explanation": "At resonance, X_L = X_C, so the net reactance is zero. The impedance Z = R (purely resistive). The phase angle φ = tan⁻¹((X_L − X_C)/R) = tan⁻¹(0) = 0°. Therefore, power factor = cos 0° = 1. Maximum power is transferred at resonance.", "correct_answer": "A", "concept_tags": ["power-factor", "resonance", "LCR-circuit"], "payload": {"question_id": "cuet-phy-ac-adv-18", "subtopic": "power factor", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "1", "is_correct": true}, {"key": "B", "value": "0", "is_correct": false}, {"key": "C", "value": "0.5", "is_correct": false}, {"key": "D", "value": "1/√2", "is_correct": false}], "elimination_hints": ["Power factor = 0 in purely reactive circuits, not at resonance.", "At resonance the circuit is purely resistive — φ = 0° → cos φ = 1.", "Power factor = 1 means maximum power transfer."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A power station delivers 500 kW of power at 10,000 V to a factory through cables of total resistance 4 Ω. The power loss in transmission is:", "explanation": "Current I = P/V = 500 × 10³/10⁴ = 50 A. Power loss = I²R = 50² × 4 = 2500 × 4 = 10,000 W = 10 kW. The percentage loss = (10/500) × 100 = 2%. This shows why high-voltage transmission reduces losses — the current is smaller for the same power.", "correct_answer": "B", "concept_tags": ["power-transmission", "transmission-loss", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-19", "subtopic": "power transmission", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "5 kW", "is_correct": false}, {"key": "B", "value": "10 kW", "is_correct": true}, {"key": "C", "value": "20 kW", "is_correct": false}, {"key": "D", "value": "50 kW", "is_correct": false}], "elimination_hints": ["I = P/V = 500000/10000 = 50 A.", "Power loss = I²R = 2500 × 4 = 10000 W = 10 kW.", "50 kW would require I²R = 50000, which doesn''t match these values."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the transmission voltage is doubled, the power loss in the cables becomes:", "explanation": "Power loss = I²R = (P/V)²R = P²R/V². If V is doubled, loss becomes P²R/(2V)² = P²R/(4V²) = original loss/4. So doubling the voltage reduces the power loss to one-fourth. This is the key reason for high-voltage power transmission.", "correct_answer": "B", "concept_tags": ["power-transmission", "voltage", "efficiency"], "payload": {"question_id": "cuet-phy-ac-adv-20", "subtopic": "power transmission", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "Half of the original", "is_correct": false}, {"key": "B", "value": "One-fourth of the original", "is_correct": true}, {"key": "C", "value": "Double the original", "is_correct": false}, {"key": "D", "value": "Same as the original", "is_correct": false}], "elimination_hints": ["Loss ∝ 1/V², so doubling V reduces loss by a factor of 4.", "Half would be correct if loss ∝ 1/V, but it''s ∝ 1/V².", "Higher voltage means lower current for same power → much less I²R loss."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The efficiency of a transformer is defined as:", "explanation": "Efficiency η = (output power / input power) × 100%. For an ideal transformer η = 100%. Real transformers have η between 90–99% due to copper losses, eddy current losses, hysteresis losses, and flux leakage.", "correct_answer": "A", "concept_tags": ["transformer", "efficiency", "power"], "payload": {"question_id": "cuet-phy-ac-adv-21", "subtopic": "transformer efficiency", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "(Output power / Input power) × 100%", "is_correct": true}, {"key": "B", "value": "(Input power / Output power) × 100%", "is_correct": false}, {"key": "C", "value": "(V_s / V_p) × 100%", "is_correct": false}, {"key": "D", "value": "(N_p / N_s) × 100%", "is_correct": false}], "elimination_hints": ["Input/Output ratio would give a value > 100% for a real transformer.", "V_s/V_p is the voltage ratio (turns ratio), not efficiency.", "Efficiency relates power output to power input, not voltages or turns."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Copper loss (I²R loss) in a transformer is due to:", "explanation": "Copper loss occurs because the primary and secondary windings have finite resistance. When current flows through these windings, energy is dissipated as heat (I²R). It can be reduced by using thick copper wires (low resistance).", "correct_answer": "C", "concept_tags": ["transformer", "copper-loss", "resistance", "heating"], "payload": {"question_id": "cuet-phy-ac-adv-22", "subtopic": "transformer losses", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "Eddy currents in the core", "is_correct": false}, {"key": "B", "value": "Hysteresis in the core", "is_correct": false}, {"key": "C", "value": "Resistance of the windings", "is_correct": true}, {"key": "D", "value": "Magnetic flux leakage", "is_correct": false}], "elimination_hints": ["Eddy currents cause iron loss, not copper loss.", "Hysteresis loss is due to repeated magnetization of the core.", "Copper loss = I²R, and R is the resistance of the copper windings."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Eddy current losses in a transformer core are minimized by:", "explanation": "Eddy currents are induced in the transformer core by the changing magnetic flux. Using a laminated core (thin insulated sheets) increases the resistance to eddy current paths, confining them to small loops within each lamination, thereby reducing I²R heating.", "correct_answer": "B", "concept_tags": ["transformer", "eddy-current-loss", "lamination"], "payload": {"question_id": "cuet-phy-ac-adv-23", "subtopic": "transformer losses", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "Using thick copper windings", "is_correct": false}, {"key": "B", "value": "Using a laminated iron core", "is_correct": true}, {"key": "C", "value": "Increasing the frequency", "is_correct": false}, {"key": "D", "value": "Using a solid iron core", "is_correct": false}], "elimination_hints": ["Thick copper windings reduce copper loss, not eddy current loss.", "Increasing frequency actually increases eddy current losses.", "A solid core allows large eddy current loops — lamination breaks them up."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Hysteresis loss in a transformer can be minimized by using a core material with:", "explanation": "Hysteresis loss is proportional to the area of the B-H (hysteresis) loop. Soft magnetic materials like soft iron or silicon steel have narrow hysteresis loops (low coercivity and low retentivity), resulting in less energy lost per magnetization cycle.", "correct_answer": "A", "concept_tags": ["transformer", "hysteresis-loss", "soft-iron", "B-H-curve"], "payload": {"question_id": "cuet-phy-ac-adv-24", "subtopic": "transformer losses", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "Narrow hysteresis loop (e.g. soft iron)", "is_correct": true}, {"key": "B", "value": "Wide hysteresis loop (e.g. steel)", "is_correct": false}, {"key": "C", "value": "High coercivity", "is_correct": false}, {"key": "D", "value": "High retentivity", "is_correct": false}], "elimination_hints": ["Wide hysteresis loop means more area → more energy loss per cycle.", "High coercivity materials (like steel) are used for permanent magnets, not transformer cores.", "Narrow loop = low coercivity + low retentivity = less hysteresis loss."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A transformer with 90% efficiency has a primary voltage of 200 V and delivers power to a 20 Ω load connected to its secondary at 40 V. The primary current drawn is approximately:", "explanation": "Secondary current I_s = V_s/R_load = 40/20 = 2 A. Output power = V_s × I_s = 40 × 2 = 80 W. Efficiency η = P_out/P_in → P_in = P_out/η = 80/0.9 ≈ 88.9 W. Primary current I_p = P_in/V_p = 88.9/200 ≈ 0.44 A.", "correct_answer": "C", "concept_tags": ["transformer", "efficiency", "numerical", "power"], "payload": {"question_id": "cuet-phy-ac-adv-25", "subtopic": "transformer efficiency", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "0.2 A", "is_correct": false}, {"key": "B", "value": "0.4 A", "is_correct": false}, {"key": "C", "value": "0.44 A", "is_correct": true}, {"key": "D", "value": "0.8 A", "is_correct": false}], "elimination_hints": ["0.4 A assumes 100% efficiency (ideal transformer).", "0.8 A comes from incorrect calculation: I_p must be greater than 0.4 A (ideal) due to losses, but not double.", "P_in = 80/0.9 ≈ 88.9 W → I_p = 88.9/200 ≈ 0.44 A."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An ideal step-down transformer converts 2200 V to 220 V. If the secondary coil has 50 turns, the number of turns in the primary coil is:", "explanation": "For an ideal transformer, V_p/V_s = N_p/N_s. So N_p = N_s × (V_p/V_s) = 50 × (2200/220) = 50 × 10 = 500 turns. The step-down ratio is 10:1.", "correct_answer": "B", "concept_tags": ["transformer", "turns-ratio", "step-down", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-26", "subtopic": "transformer calculations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "50", "is_correct": false}, {"key": "B", "value": "500", "is_correct": true}, {"key": "C", "value": "5000", "is_correct": false}, {"key": "D", "value": "5", "is_correct": false}], "elimination_hints": ["50 turns for primary would mean a 1:1 ratio, not a step-down.", "V_p/V_s = 2200/220 = 10, so N_p = 10 × N_s = 10 × 50 = 500.", "5000 would require a 100:1 ratio which doesn''t match 2200:220."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a transformer, flux leakage leads to:", "explanation": "Flux leakage means not all the magnetic flux produced by the primary coil links with the secondary coil. This reduces the EMF induced in the secondary, decreasing the output voltage and power. It reduces the efficiency of the transformer.", "correct_answer": "D", "concept_tags": ["transformer", "flux-leakage", "efficiency"], "payload": {"question_id": "cuet-phy-ac-adv-27", "subtopic": "transformer losses", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "Increased output voltage", "is_correct": false}, {"key": "B", "value": "Increased efficiency", "is_correct": false}, {"key": "C", "value": "No effect on performance", "is_correct": false}, {"key": "D", "value": "Reduced output voltage and efficiency", "is_correct": true}], "elimination_hints": ["Less flux linking secondary means less induced EMF → lower output voltage.", "Flux leakage is a loss mechanism — it reduces efficiency, not increases it.", "Any energy lost to leakage flux is energy not transferred to the secondary."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A town 10 km away receives electrical power from a power plant. The power plant generates 2 MW at 10 kV. The two-wire transmission line has a resistance of 0.5 Ω/km. The power loss in the line is:", "explanation": "Total wire length = 2 × 10 = 20 km (two wires). Total resistance R = 20 × 0.5 = 10 Ω. Current I = P/V = 2 × 10⁶ / (10 × 10³) = 200 A. Power loss = I²R = 200² × 10 = 40000 × 10 = 400,000 W = 400 kW. Percentage loss = (400/2000) × 100 = 20%.", "correct_answer": "C", "concept_tags": ["power-transmission", "line-loss", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-28", "subtopic": "power transmission", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "100 kW", "is_correct": false}, {"key": "B", "value": "200 kW", "is_correct": false}, {"key": "C", "value": "400 kW", "is_correct": true}, {"key": "D", "value": "800 kW", "is_correct": false}], "elimination_hints": ["Two wires of 10 km each → total resistance = 20 × 0.5 = 10 Ω.", "I = 2 × 10⁶ / 10⁴ = 200 A; Loss = 200² × 10 = 400,000 W.", "200 kW uses only one wire''s resistance (5 Ω) — must count both wires."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an LC oscillating circuit, the capacitor has maximum charge q₀ and the inductance is L. The maximum current in the circuit is:", "explanation": "By energy conservation: ½q₀²/C = ½LI₀². Also, I₀ = q₀ω = q₀/√(LC). Alternatively, from ½q₀²/C = ½LI₀², we get I₀ = q₀/√(LC). The maximum current occurs when the capacitor is fully discharged.", "correct_answer": "A", "concept_tags": ["LC-oscillation", "maximum-current", "energy-conservation"], "payload": {"question_id": "cuet-phy-ac-adv-29", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "q₀/√(LC)", "is_correct": true}, {"key": "B", "value": "q₀√(LC)", "is_correct": false}, {"key": "C", "value": "q₀/(LC)", "is_correct": false}, {"key": "D", "value": "q₀√(L/C)", "is_correct": false}], "elimination_hints": ["q₀√(LC) has dimensions of charge × time, not current.", "I₀ = q₀ω = q₀ × 1/√(LC) = q₀/√(LC).", "Dimensional check: [q₀/√(LC)] = C/√(H·F) = C/√(s²) = C/s = A ✓"]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An LC circuit has L = 0.2 H and C = 5 μF. The capacitor is initially charged to 10 mC. The maximum current in the circuit is:", "explanation": "I₀ = q₀/√(LC) = 10 × 10⁻³ / √(0.2 × 5 × 10⁻⁶) = 10⁻² / √(10⁻⁶) = 10⁻² / 10⁻³ = 10 A. Alternatively, ω = 1/√(LC) = 1/10⁻³ = 1000 rad/s, and I₀ = q₀ω = 10⁻² × 10³ = 10 A.", "correct_answer": "D", "concept_tags": ["LC-oscillation", "maximum-current", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-30", "subtopic": "LC oscillations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "0.1 A", "is_correct": false}, {"key": "B", "value": "1 A", "is_correct": false}, {"key": "C", "value": "5 A", "is_correct": false}, {"key": "D", "value": "10 A", "is_correct": true}], "elimination_hints": ["LC = 0.2 × 5 × 10⁻⁶ = 10⁻⁶, so √(LC) = 10⁻³.", "I₀ = q₀/√(LC) = 10 × 10⁻³ / 10⁻³ = 10 A.", "Common error: forgetting to convert mC to C gives I₀ = 10000 A (way too high)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In the LC-SHM analogy, the quantity analogous to the potential energy (½kx²) of the spring-mass system is:", "explanation": "In the analogy: q ↔ x, I ↔ v, L ↔ m, 1/C ↔ k. Potential energy ½kx² ↔ ½(1/C)q² = q²/(2C), which is the energy stored in the capacitor (electric field energy). Kinetic energy ½mv² ↔ ½LI² (magnetic energy in the inductor).", "correct_answer": "B", "concept_tags": ["LC-oscillation", "SHM-analogy", "energy"], "payload": {"question_id": "cuet-phy-ac-adv-31", "subtopic": "LC oscillations — SHM analogy", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "½LI² (energy in inductor)", "is_correct": false}, {"key": "B", "value": "q²/(2C) (energy in capacitor)", "is_correct": true}, {"key": "C", "value": "½CV² (energy in capacitor)", "is_correct": false}, {"key": "D", "value": "LI (flux linkage)", "is_correct": false}], "elimination_hints": ["½LI² is analogous to ½mv² (kinetic energy), not potential energy.", "½CV² is the same as q²/(2C) but written in terms of V; the direct analogy uses q (↔ x).", "Potential energy involves the ''displacement'' variable: ½kx² ↔ q²/(2C)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following is NOT a source of energy loss in a real transformer?", "explanation": "Energy losses in a real transformer include: copper loss (I²R in windings), eddy current loss (induced currents in core), hysteresis loss (repeated magnetization of core), and flux leakage. Dielectric loss occurs in capacitors, not in transformers.", "correct_answer": "D", "concept_tags": ["transformer", "energy-loss", "efficiency"], "payload": {"question_id": "cuet-phy-ac-adv-32", "subtopic": "transformer losses", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "Copper loss", "is_correct": false}, {"key": "B", "value": "Eddy current loss", "is_correct": false}, {"key": "C", "value": "Hysteresis loss", "is_correct": false}, {"key": "D", "value": "Dielectric loss", "is_correct": true}], "elimination_hints": ["Copper loss (I²R) definitely occurs in the windings.", "Eddy current and hysteresis losses occur in the iron core.", "Dielectric loss is associated with capacitors and insulators, not transformer operation."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A step-up transformer has a turns ratio of 1:10. If the primary current is 5 A, the secondary current for an ideal transformer is:", "explanation": "For an ideal transformer, I_p/I_s = N_s/N_p (current is inversely proportional to turns ratio). I_s = I_p × (N_p/N_s) = 5 × (1/10) = 0.5 A. A step-up transformer increases voltage but decreases current proportionally.", "correct_answer": "A", "concept_tags": ["transformer", "current-ratio", "step-up", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-33", "subtopic": "transformer calculations", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "0.5 A", "is_correct": true}, {"key": "B", "value": "5 A", "is_correct": false}, {"key": "C", "value": "50 A", "is_correct": false}, {"key": "D", "value": "0.05 A", "is_correct": false}], "elimination_hints": ["5 A would mean no change in current (1:1 transformer).", "50 A would mean the current increased — this happens in a step-down, not step-up.", "In a step-up transformer, voltage increases so current must decrease: I_s = 5/10 = 0.5 A."]}}]'::jsonb, 'deploy-2026-03-05-b06');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Assertion (A): A transformer cannot work with direct current (DC).\nReason (R): A transformer works on the principle of mutual induction which requires a changing magnetic flux.", "explanation": "DC produces a constant current and hence a constant magnetic flux in the primary. A constant flux does not induce any EMF in the secondary (Faraday''s law: EMF = −dΦ/dt = 0 for constant Φ). Moreover, with DC, the primary acts as a short circuit (only resistance, no reactance), drawing excessive current that can burn the windings.", "correct_answer": "A", "concept_tags": ["transformer", "DC", "mutual-induction", "assertion-reason"], "payload": {"question_id": "cuet-phy-ac-adv-34", "subtopic": "transformer principle", "topic_name": "AC Circuits — Advanced", "bloom_level": "evaluate", "options": [{"key": "A", "value": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "value": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "value": "A is true but R is false", "is_correct": false}, {"key": "D", "value": "A is false but R is true", "is_correct": false}], "elimination_hints": ["The transformer indeed cannot work with DC — assertion A is true.", "Mutual induction requires dΦ/dt ≠ 0, which needs AC — reason R is true.", "R directly explains A: the changing flux requirement is why DC fails."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an LCR circuit connected to an AC source, the current is in phase with the voltage. This means:", "explanation": "Current in phase with voltage means φ = 0°, which occurs when X_L = X_C (reactances cancel). This is the condition for resonance in a series LCR circuit. At resonance, Z = R (minimum impedance) and current is maximum.", "correct_answer": "C", "concept_tags": ["resonance", "phase", "LCR-circuit"], "payload": {"question_id": "cuet-phy-ac-adv-35", "subtopic": "resonance conditions", "topic_name": "AC Circuits — Advanced", "bloom_level": "understand", "options": [{"key": "A", "value": "X_L > X_C", "is_correct": false}, {"key": "B", "value": "X_L < X_C", "is_correct": false}, {"key": "C", "value": "X_L = X_C (resonance)", "is_correct": true}, {"key": "D", "value": "R = 0", "is_correct": false}], "elimination_hints": ["X_L > X_C makes the circuit inductive — current lags voltage.", "X_L < X_C makes the circuit capacitive — current leads voltage.", "In-phase condition requires net reactance = 0, i.e., X_L = X_C."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In an LCR series circuit, R = 10 Ω, L = 0.5 H, and C = 50 μF. The circuit is connected to a 220 V, 50 Hz AC source. The current in the circuit is approximately:", "explanation": "ω = 2πf = 2π × 50 = 100π rad/s. X_L = ωL = 100π × 0.5 = 50π ≈ 157 Ω. X_C = 1/(ωC) = 1/(100π × 50 × 10⁻⁶) = 1/(5π × 10⁻³) = 200/π ≈ 63.7 Ω. Z = √(R² + (X_L − X_C)²) = √(100 + (157 − 63.7)²) = √(100 + 8700) = √8800 ≈ 93.8 Ω. I = V/Z = 220/93.8 ≈ 2.34 A.", "correct_answer": "B", "concept_tags": ["LCR-circuit", "impedance", "numerical", "current"], "payload": {"question_id": "cuet-phy-ac-adv-36", "subtopic": "LCR circuit numerical", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "1.0 A", "is_correct": false}, {"key": "B", "value": "2.3 A", "is_correct": true}, {"key": "C", "value": "5.0 A", "is_correct": false}, {"key": "D", "value": "22.0 A", "is_correct": false}], "elimination_hints": ["22.0 A would require Z = 10 Ω (only R), ignoring reactances.", "X_L − X_C ≈ 93 Ω, so Z ≈ √(100 + 8700) ≈ 94 Ω.", "I = 220/94 ≈ 2.3 A."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In the above circuit (R = 10 Ω, L = 0.5 H, C = 50 μF, f = 50 Hz), the resonant frequency is approximately:", "explanation": "f₀ = 1/(2π√(LC)) = 1/(2π√(0.5 × 50 × 10⁻⁶)) = 1/(2π√(25 × 10⁻⁶)) = 1/(2π × 5 × 10⁻³) = 1/(10π × 10⁻³) = 1000/(10π) = 100/π ≈ 31.8 Hz. The circuit is being driven at 50 Hz, which is above resonance.", "correct_answer": "A", "concept_tags": ["resonant-frequency", "LCR-circuit", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-37", "subtopic": "LCR circuit numerical", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "100/π Hz ≈ 31.8 Hz", "is_correct": true}, {"key": "B", "value": "50 Hz", "is_correct": false}, {"key": "C", "value": "100 Hz", "is_correct": false}, {"key": "D", "value": "200/π Hz ≈ 63.7 Hz", "is_correct": false}], "elimination_hints": ["50 Hz is the driving frequency, not the resonant frequency.", "LC = 0.5 × 50 × 10⁻⁶ = 25 × 10⁻⁶, √(LC) = 5 × 10⁻³.", "f₀ = 1/(2π × 5 × 10⁻³) = 100/π ≈ 31.8 Hz."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The power factor of a series RL circuit with R = 30 Ω and X_L = 40 Ω is:", "explanation": "Power factor cos φ = R/Z. Impedance Z = √(R² + X_L²) = √(900 + 1600) = √2500 = 50 Ω. cos φ = R/Z = 30/50 = 0.6. The phase angle φ = cos⁻¹(0.6) ≈ 53.13°.", "correct_answer": "C", "concept_tags": ["power-factor", "RL-circuit", "impedance", "numerical"], "payload": {"question_id": "cuet-phy-ac-adv-38", "subtopic": "power factor", "topic_name": "AC Circuits — Advanced", "bloom_level": "apply", "options": [{"key": "A", "value": "0.4", "is_correct": false}, {"key": "B", "value": "0.5", "is_correct": false}, {"key": "C", "value": "0.6", "is_correct": true}, {"key": "D", "value": "0.8", "is_correct": false}], "elimination_hints": ["0.8 = 40/50 = X_L/Z, which is sin φ, not cos φ.", "0.4 = R/X_L — this is not the power factor formula.", "Power factor = R/Z = 30/50 = 0.6. It''s a 3-4-5 right triangle scaled by 10."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Match the following AC circuit parameters (Column-I) with their expressions (Column-II):\nColumn-I: (P) Impedance of LCR circuit (Q) Resonant frequency (R) Power factor (S) Q-factor\nColumn-II: (1) R/Z (2) √(R² + (X_L − X_C)²) (3) ω₀L/R (4) 1/(2π√(LC))", "explanation": "(P) Impedance Z = √(R² + (X_L − X_C)²) → (2). (Q) Resonant frequency f₀ = 1/(2π√(LC)) → (4). (R) Power factor cos φ = R/Z → (1). (S) Q-factor = ω₀L/R → (3).", "correct_answer": "B", "concept_tags": ["LCR-circuit", "matching", "formulas"], "payload": {"question_id": "cuet-phy-ac-adv-39", "subtopic": "AC circuit formulas", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "P→1, Q→2, R→3, S→4", "is_correct": false}, {"key": "B", "value": "P→2, Q→4, R→1, S→3", "is_correct": true}, {"key": "C", "value": "P→2, Q→3, R→4, S→1", "is_correct": false}, {"key": "D", "value": "P→4, Q→2, R→3, S→1", "is_correct": false}], "elimination_hints": ["Impedance involves square root of R² plus reactance difference squared → (2).", "Resonant frequency has 1/(2π√(LC)) → (4).", "Power factor = cos φ = R/Z → (1); Q = ω₀L/R → (3)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Assertion (A): At resonance in a series LCR circuit, the voltage across the inductor can be much greater than the applied voltage.\nReason (R): The Q-factor of the circuit amplifies the voltage across individual reactive components at resonance.", "explanation": "At resonance, V_L = IX_L = (V/R)(ω₀L) = V(ω₀L/R) = VQ. Since Q can be much greater than 1 (e.g., Q = 50), the voltage across L (or C) can be 50 times the applied voltage. This voltage amplification is the essence of the Q-factor. Both A and R are true, and R correctly explains A.", "correct_answer": "A", "concept_tags": ["resonance", "Q-factor", "voltage-amplification", "assertion-reason"], "payload": {"question_id": "cuet-phy-ac-adv-40", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "evaluate", "options": [{"key": "A", "value": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "value": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "value": "A is true but R is false", "is_correct": false}, {"key": "D", "value": "A is false but R is true", "is_correct": false}], "elimination_hints": ["V_L = VQ at resonance, and Q can be >> 1, so V_L >> V. Assertion A is true.", "The Q-factor is precisely the ratio V_L/V (or V_C/V) at resonance. Reason R is true.", "R directly explains A — the voltage amplification is due to the Q-factor."]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-elements", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The three essential elements of a communication system are:", "explanation": "Every communication system consists of three fundamental blocks: (1) Transmitter — converts the message signal into a form suitable for transmission, (2) Channel — the physical medium through which the signal travels (wire, free space, optical fibre), and (3) Receiver — extracts the original message from the received signal.", "correct_answer": "A", "concept_tags": ["communication-elements", "transmitter", "receiver", "channel"], "payload": {"question_id": "cuet-phy-comm-01", "subtopic": "basic blocks", "topic_name": "Elements of Communication System", "bloom_level": "remember", "options": [{"key": "A", "text": "Transmitter, Channel, Receiver", "is_correct": true}, {"key": "B", "text": "Oscillator, Amplifier, Antenna", "is_correct": false}, {"key": "C", "text": "Modulator, Demodulator, Amplifier", "is_correct": false}, {"key": "D", "text": "Encoder, Decoder, Repeater", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Oscillator, amplifier and antenna are components within a transmitter, not the three main blocks of the system.", "misconception": "Confusing sub-components with main elements"}, {"option_key": "C", "hint": "Modulator and demodulator are parts of the transmitter and receiver respectively, not the three fundamental elements.", "misconception": "Listing processes instead of system blocks"}, {"option_key": "D", "hint": "Encoder and decoder are used in digital communication. Repeater is an intermediate device. These are not the three fundamental elements.", "misconception": "Mixing digital communication terms with basic structure"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-elements", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A transducer in a communication system is a device that:", "explanation": "A transducer converts one form of energy into another. In communication, the transmitting transducer converts the message (sound, image, data) into an electrical signal. For example, a microphone converts sound energy into electrical energy, and a camera converts light into electrical signals.", "correct_answer": "B", "concept_tags": ["transducer", "energy-conversion", "input-device"], "payload": {"question_id": "cuet-phy-comm-02", "subtopic": "transducer", "topic_name": "Elements of Communication System", "bloom_level": "remember", "options": [{"key": "A", "text": "Amplifies the signal", "is_correct": false}, {"key": "B", "text": "Converts one form of energy into another", "is_correct": true}, {"key": "C", "text": "Filters unwanted frequencies", "is_correct": false}, {"key": "D", "text": "Modulates the carrier wave", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Signal amplification is done by an amplifier, not a transducer.", "misconception": "Confusing transducer with amplifier"}, {"option_key": "C", "hint": "Filtering unwanted frequencies is done by a band-pass filter, not a transducer.", "misconception": "Confusing transducer with filter"}, {"option_key": "D", "hint": "Modulation is done by a modulator circuit. A transducer only converts the physical signal to electrical form.", "misconception": "Confusing transducer with modulator"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-elements", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The process of retrieving the original message signal from the modulated carrier wave at the receiver is called:", "explanation": "Demodulation (or detection) is the process of extracting the original message signal from the modulated carrier wave. It is the reverse of modulation and is performed at the receiver end. For AM signals, an envelope detector is commonly used for demodulation.", "correct_answer": "C", "concept_tags": ["demodulation", "detection", "receiver"], "payload": {"question_id": "cuet-phy-comm-03", "subtopic": "demodulation", "topic_name": "Elements of Communication System", "bloom_level": "remember", "options": [{"key": "A", "text": "Modulation", "is_correct": false}, {"key": "B", "text": "Amplification", "is_correct": false}, {"key": "C", "text": "Demodulation", "is_correct": true}, {"key": "D", "text": "Transmission", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Modulation is the opposite process — it combines the message with a carrier at the transmitter, not recovery at receiver.", "misconception": "Confusing modulation with demodulation"}, {"option_key": "B", "hint": "Amplification increases signal strength but does not extract the original message from the carrier.", "misconception": "Confusing signal strengthening with message recovery"}, {"option_key": "D", "hint": "Transmission is sending the signal through the channel, not recovering the message.", "misconception": "Confusing the sending process with the receiving process"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-bandwidth", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The bandwidth of a speech signal for telephonic communication is approximately:", "explanation": "For telephone-quality speech, the frequency range is approximately 300 Hz to 3400 Hz, giving a bandwidth of about 3100 Hz ≈ 3 kHz. Music requires higher bandwidth (~20 kHz), and video requires even more (~4.2 MHz for analog TV).", "correct_answer": "A", "concept_tags": ["bandwidth", "speech-signal", "frequency-range"], "payload": {"question_id": "cuet-phy-comm-04", "subtopic": "signal bandwidth", "topic_name": "Bandwidth of Signals and Channels", "bloom_level": "remember", "options": [{"key": "A", "text": "3 kHz", "is_correct": true}, {"key": "B", "text": "20 kHz", "is_correct": false}, {"key": "C", "text": "4.2 MHz", "is_correct": false}, {"key": "D", "text": "300 MHz", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "20 kHz is the bandwidth of high-fidelity music signals (20 Hz to 20 kHz), not telephonic speech.", "misconception": "Confusing speech bandwidth with audio bandwidth"}, {"option_key": "C", "hint": "4.2 MHz is the bandwidth of an analog video/TV signal, far more than what speech requires.", "misconception": "Confusing speech with video bandwidth"}, {"option_key": "D", "hint": "300 MHz is a carrier frequency range, not a message signal bandwidth.", "misconception": "Confusing carrier frequency with signal bandwidth"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-bandwidth", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If an audio signal of 10 kHz is used to modulate a carrier of 1 MHz, the bandwidth of the AM signal is:", "explanation": "In amplitude modulation, the modulated signal contains the carrier frequency fc and two sidebands: (fc + fm) and (fc − fm). The bandwidth = 2fm = 2 × 10 kHz = 20 kHz. The AM signal occupies from (1000 − 10) kHz to (1000 + 10) kHz = 990 kHz to 1010 kHz.", "correct_answer": "B", "concept_tags": ["AM-bandwidth", "sidebands", "twice-modulating-frequency"], "payload": {"question_id": "cuet-phy-comm-05", "subtopic": "AM signal bandwidth", "topic_name": "Bandwidth of Signals and Channels", "bloom_level": "apply", "options": [{"key": "A", "text": "10 kHz", "is_correct": false}, {"key": "B", "text": "20 kHz", "is_correct": true}, {"key": "C", "text": "1 MHz", "is_correct": false}, {"key": "D", "text": "1.01 MHz", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10 kHz is the modulating frequency fm. Bandwidth of AM = 2fm because there are two sidebands.", "misconception": "Forgetting that AM has two sidebands (upper and lower)"}, {"option_key": "C", "hint": "1 MHz is the carrier frequency, not the bandwidth. Bandwidth is the range of frequencies occupied by the modulated signal.", "misconception": "Confusing carrier frequency with bandwidth"}, {"option_key": "D", "hint": "1.01 MHz is the upper sideband frequency (fc + fm), not the bandwidth.", "misconception": "Confusing sideband frequency with bandwidth"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Ground wave propagation is suitable for frequencies:", "explanation": "Ground wave propagation works for frequencies below about 2 MHz. The radio waves follow the curvature of the Earth along its surface. At higher frequencies, the ground absorbs more energy, making ground wave propagation ineffective. AM radio broadcasting (530–1710 kHz) uses ground wave propagation.", "correct_answer": "A", "concept_tags": ["ground-wave", "low-frequency", "propagation-mode"], "payload": {"question_id": "cuet-phy-comm-06", "subtopic": "ground wave propagation", "topic_name": "Propagation of EM Waves", "bloom_level": "remember", "options": [{"key": "A", "text": "Up to 2 MHz", "is_correct": true}, {"key": "B", "text": "2 MHz to 30 MHz", "is_correct": false}, {"key": "C", "text": "30 MHz to 300 MHz", "is_correct": false}, {"key": "D", "text": "Above 300 MHz", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "2–30 MHz (short wave) is the range for sky wave (ionospheric) propagation, not ground wave.", "misconception": "Confusing ground wave with sky wave frequency range"}, {"option_key": "C", "hint": "30–300 MHz (VHF) uses space wave (line-of-sight) propagation, not ground wave.", "misconception": "Confusing ground wave with space wave"}, {"option_key": "D", "hint": "Above 300 MHz (UHF and beyond) uses space wave/satellite communication. Ground absorption is too high.", "misconception": "Thinking higher frequency means better ground propagation"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Sky wave propagation is used for long-distance communication using the reflection of radio waves from the:", "explanation": "Sky wave propagation relies on the ionosphere — a layer of the atmosphere (80–400 km altitude) containing ionised gases. The ionosphere reflects radio waves in the frequency range 2–30 MHz back to Earth. This allows communication over thousands of kilometres by successive reflections between the ionosphere and Earth''s surface.", "correct_answer": "B", "concept_tags": ["sky-wave", "ionosphere", "reflection"], "payload": {"question_id": "cuet-phy-comm-07", "subtopic": "sky wave propagation", "topic_name": "Propagation of EM Waves", "bloom_level": "remember", "options": [{"key": "A", "text": "Troposphere", "is_correct": false}, {"key": "B", "text": "Ionosphere", "is_correct": true}, {"key": "C", "text": "Stratosphere", "is_correct": false}, {"key": "D", "text": "Ozone layer", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The troposphere (0–12 km) causes weather effects on signals but does not reflect radio waves like the ionosphere does.", "misconception": "Confusing troposphere with ionosphere"}, {"option_key": "C", "hint": "The stratosphere (12–50 km) contains the ozone layer but lacks the free electrons needed to reflect radio waves.", "misconception": "Mixing up atmospheric layers"}, {"option_key": "D", "hint": "The ozone layer absorbs UV radiation but does not reflect radio waves. Radio wave reflection needs free electrons.", "misconception": "Confusing UV absorption with radio wave reflection"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The maximum range of a TV transmitting tower of height h above the Earth''s surface is given by d = √(2Rh), where R is the radius of Earth. If the tower height is doubled, the range becomes:", "explanation": "Range d = √(2Rh). If h is doubled: d'' = √(2R × 2h) = √(2 × 2Rh) = √2 × √(2Rh) = √2 × d. So the range increases by a factor of √2, i.e., d'' = √2 d ≈ 1.414d.", "correct_answer": "C", "concept_tags": ["tower-range", "line-of-sight", "height-dependence"], "payload": {"question_id": "cuet-phy-comm-08", "subtopic": "space wave range formula", "topic_name": "Propagation of EM Waves", "bloom_level": "apply", "options": [{"key": "A", "text": "2d", "is_correct": false}, {"key": "B", "text": "4d", "is_correct": false}, {"key": "C", "text": "√2 d", "is_correct": true}, {"key": "D", "text": "d/√2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "d is proportional to √h, not h. Doubling h gives √2 × d, not 2d.", "misconception": "Assuming linear relationship between range and height"}, {"option_key": "B", "hint": "4d would require h to increase 16 times (since d ∝ √h, d'' = 4d requires h'' = 16h).", "misconception": "Squaring instead of taking square root"}, {"option_key": "D", "hint": "d/√2 means the range decreases, which contradicts the fact that a taller tower should have greater range.", "misconception": "Inverting the relationship"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The main reason for modulation in communication is:", "explanation": "Audio signals (20 Hz – 20 kHz) have wavelengths of 15 km to 15,000 km. An antenna needs to be at least λ/4 long to radiate efficiently, which would require impractically large antennas. By modulating onto a high-frequency carrier, the effective wavelength becomes much smaller, allowing practical antenna sizes.", "correct_answer": "D", "concept_tags": ["need-for-modulation", "antenna-size", "practical"], "payload": {"question_id": "cuet-phy-comm-09", "subtopic": "need for modulation", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "understand", "options": [{"key": "A", "text": "To increase the power of the signal", "is_correct": false}, {"key": "B", "text": "To reduce noise in the signal", "is_correct": false}, {"key": "C", "text": "To convert analog to digital", "is_correct": false}, {"key": "D", "text": "To enable transmission using antennas of practical size", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Amplifiers increase power. Modulation shifts the frequency band, it does not increase power.", "misconception": "Confusing modulation with amplification"}, {"option_key": "B", "hint": "While FM has better noise immunity than AM, noise reduction is not the primary reason for modulation.", "misconception": "Confusing a secondary benefit with the main purpose"}, {"option_key": "C", "hint": "Analog-to-digital conversion is digitisation, not modulation. AM and FM are analog modulation techniques.", "misconception": "Confusing modulation with digitisation"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In amplitude modulation, which property of the carrier wave is varied?", "explanation": "In amplitude modulation (AM), the amplitude of the high-frequency carrier wave is varied in accordance with the instantaneous value of the modulating (message) signal. The frequency and phase of the carrier remain constant. In FM, the frequency is varied; in PM, the phase is varied.", "correct_answer": "A", "concept_tags": ["amplitude-modulation", "carrier-amplitude", "AM-definition"], "payload": {"question_id": "cuet-phy-comm-10", "subtopic": "definition of AM", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "remember", "options": [{"key": "A", "text": "Amplitude", "is_correct": true}, {"key": "B", "text": "Frequency", "is_correct": false}, {"key": "C", "text": "Phase", "is_correct": false}, {"key": "D", "text": "Wavelength and amplitude both", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Varying frequency is frequency modulation (FM), not amplitude modulation.", "misconception": "Confusing AM with FM"}, {"option_key": "C", "hint": "Varying phase is phase modulation (PM), a different technique from AM.", "misconception": "Confusing AM with PM"}, {"option_key": "D", "hint": "In AM, only the amplitude changes. The frequency (and hence wavelength) of the carrier stays constant.", "misconception": "Thinking multiple properties change simultaneously in AM"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The modulation index of an AM wave is 0.6. The ratio of the maximum amplitude to the minimum amplitude of the modulated wave is:", "explanation": "For AM, Amax = Ac(1 + m) and Amin = Ac(1 − m), where m is the modulation index. Ratio = Amax/Amin = (1 + m)/(1 − m) = (1 + 0.6)/(1 − 0.6) = 1.6/0.4 = 4.", "correct_answer": "C", "concept_tags": ["modulation-index", "Amax-Amin", "numerical"], "payload": {"question_id": "cuet-phy-comm-11", "subtopic": "modulation index calculation", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "1.6", "is_correct": false}, {"key": "B", "text": "2.5", "is_correct": false}, {"key": "C", "text": "4", "is_correct": true}, {"key": "D", "text": "0.6", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1.6 is (1 + m), the maximum amplitude relative to carrier. The question asks the ratio Amax/Amin.", "misconception": "Calculating Amax/Ac instead of Amax/Amin"}, {"option_key": "B", "hint": "2.5 is 1/Amin = 1/0.4 — not the correct ratio. You need (1+m)/(1−m).", "misconception": "Arithmetic error in ratio calculation"}, {"option_key": "D", "hint": "0.6 is the modulation index itself, not the amplitude ratio.", "misconception": "Restating the given value as the answer"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "For an AM wave, the carrier frequency is 1 MHz and the modulating frequency is 5 kHz. The frequencies of the upper and lower sidebands are:", "explanation": "In AM, the upper sideband (USB) frequency = fc + fm = 1000 + 5 = 1005 kHz, and the lower sideband (LSB) frequency = fc − fm = 1000 − 5 = 995 kHz. The AM spectrum consists of three frequencies: LSB, carrier, and USB.", "correct_answer": "A", "concept_tags": ["sidebands", "USB-LSB", "AM-spectrum"], "payload": {"question_id": "cuet-phy-comm-12", "subtopic": "sideband frequencies", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "1005 kHz and 995 kHz", "is_correct": true}, {"key": "B", "text": "1050 kHz and 950 kHz", "is_correct": false}, {"key": "C", "text": "1005 MHz and 995 MHz", "is_correct": false}, {"key": "D", "text": "1500 kHz and 500 kHz", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "1050 and 950 kHz means fm = 50 kHz, not 5 kHz. Check unit conversion: 5 kHz = 5 kHz, not 50 kHz.", "misconception": "Adding an extra zero to the modulating frequency"}, {"option_key": "C", "hint": "The units are wrong — sidebands are in kHz (near 1000 kHz = 1 MHz), not in MHz.", "misconception": "Using wrong units — MHz instead of kHz"}, {"option_key": "D", "hint": "1500 and 500 kHz would mean fm = 500 kHz = 0.5 MHz, not 5 kHz. Massive arithmetic error.", "misconception": "Confusing kHz with MHz in the modulating frequency"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The modulation index of an AM signal is 0.5. The fraction of total power carried by the carrier is:", "explanation": "In AM, total power Pt = Pc(1 + m²/2), where Pc is carrier power. Fraction of power in carrier = Pc/Pt = 1/(1 + m²/2) = 1/(1 + 0.25/2) = 1/(1 + 0.125) = 1/1.125 = 8/9 ≈ 0.889 or 88.9%. This shows that in AM, most power is wasted in the carrier which carries no information.", "correct_answer": "B", "concept_tags": ["AM-power", "carrier-power-fraction", "efficiency"], "payload": {"question_id": "cuet-phy-comm-13", "subtopic": "power in AM", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "1/2", "is_correct": false}, {"key": "B", "text": "8/9", "is_correct": true}, {"key": "C", "text": "4/5", "is_correct": false}, {"key": "D", "text": "2/3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1/2 would mean half the power in carrier, which only happens at m = √2 (over-modulation). For m = 0.5, the carrier carries much more.", "misconception": "Guessing without using the formula"}, {"option_key": "C", "hint": "4/5 = 0.8 corresponds to m²/2 = 0.25, i.e., m = √0.5 ≈ 0.707, not 0.5.", "misconception": "Using wrong value for m in the formula"}, {"option_key": "D", "hint": "2/3 = 0.667 corresponds to m²/2 = 0.5, i.e., m = 1. Not 0.5.", "misconception": "Substituting m = 1 instead of m = 0.5"}]}}]'::jsonb, 'deploy-2026-03-05-b06');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An audio signal of 3 kHz is amplitude modulated with a carrier of 810 kHz. The frequencies present in the AM wave are:", "explanation": "An AM wave contains three frequency components: the carrier frequency fc = 810 kHz, the upper sideband fc + fm = 810 + 3 = 813 kHz, and the lower sideband fc − fm = 810 − 3 = 807 kHz. These three discrete frequencies make up the AM spectrum.", "correct_answer": "D", "concept_tags": ["AM-frequencies", "three-components", "spectrum"], "payload": {"question_id": "cuet-phy-comm-14", "subtopic": "AM wave frequency components", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "810 kHz only", "is_correct": false}, {"key": "B", "text": "807 kHz and 813 kHz only", "is_correct": false}, {"key": "C", "text": "3 kHz, 810 kHz, and 813 kHz", "is_correct": false}, {"key": "D", "text": "807 kHz, 810 kHz, and 813 kHz", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "810 kHz alone is an unmodulated carrier. Modulation creates additional sideband frequencies.", "misconception": "Thinking modulation doesn''t create new frequencies"}, {"option_key": "B", "hint": "The carrier frequency is always present in AM — it''s the dominant component. You cannot omit it.", "misconception": "Thinking AM suppresses the carrier"}, {"option_key": "C", "hint": "The original modulating frequency (3 kHz) is NOT present in the AM wave. Only fc, fc+fm, and fc−fm appear.", "misconception": "Thinking the baseband signal appears directly in the AM wave"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A TV tower has a height of 100 m. The maximum distance up to which the TV transmission can be received is: (Take R = 6.4 × 10⁶ m)", "explanation": "Using d = √(2Rh) = √(2 × 6.4 × 10⁶ × 100) = √(12.8 × 10⁸) = √(1.28 × 10⁹) = 3.58 × 10⁴ m ≈ 35.8 km.", "correct_answer": "B", "concept_tags": ["tower-range-numerical", "line-of-sight", "space-wave"], "payload": {"question_id": "cuet-phy-comm-15", "subtopic": "range calculation", "topic_name": "Propagation of EM Waves", "bloom_level": "apply", "options": [{"key": "A", "text": "25.3 km", "is_correct": false}, {"key": "B", "text": "35.8 km", "is_correct": true}, {"key": "C", "text": "50.5 km", "is_correct": false}, {"key": "D", "text": "71.6 km", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "25.3 km corresponds to using d = √(Rh) instead of d = √(2Rh) — the factor of 2 is missing.", "misconception": "Forgetting the factor of 2 in the formula"}, {"option_key": "C", "hint": "50.5 km would correspond to h ≈ 200 m. Check: √(2 × 6.4 × 10⁶ × 200) ≈ 50.6 km.", "misconception": "Using h = 200 m instead of 100 m"}, {"option_key": "D", "hint": "71.6 km is 2 × 35.8 km. Range is proportional to √h, not h.", "misconception": "Using d = 2Rh or d = 2√(2Rh)"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-detection", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In the process of AM detection, the component that removes the high-frequency carrier from the rectified signal is:", "explanation": "After rectification (using a diode), the signal still contains the high-frequency carrier ripple superimposed on the message signal. A low-pass filter (typically an RC circuit) removes the high-frequency carrier components and passes only the low-frequency message signal (envelope). This process is called envelope detection.", "correct_answer": "B", "concept_tags": ["detection", "envelope-detector", "low-pass-filter"], "payload": {"question_id": "cuet-phy-comm-16", "subtopic": "AM detection circuit", "topic_name": "Detection and Demodulation", "bloom_level": "understand", "options": [{"key": "A", "text": "High-pass filter", "is_correct": false}, {"key": "B", "text": "Low-pass filter", "is_correct": true}, {"key": "C", "text": "Band-pass filter", "is_correct": false}, {"key": "D", "text": "Oscillator", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A high-pass filter would do the opposite — pass the carrier and remove the message signal.", "misconception": "Confusing low-pass and high-pass filter functions"}, {"option_key": "C", "hint": "A band-pass filter passes a specific band. In detection, we need to remove the carrier entirely, which a low-pass filter does.", "misconception": "Confusing the filter used in tuning with detection"}, {"option_key": "D", "hint": "An oscillator generates signals (used in the transmitter for carrier generation), not for filtering.", "misconception": "Confusing signal generation with signal filtering"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The maximum modulation index for distortion-free AM is:", "explanation": "The modulation index m = Am/Ac, where Am is the message amplitude and Ac is the carrier amplitude. For distortion-free AM, m must satisfy 0 ≤ m ≤ 1. When m > 1 (over-modulation), the envelope of the AM wave gets distorted, causing the recovered signal to not faithfully reproduce the original message.", "correct_answer": "C", "concept_tags": ["modulation-index-limit", "over-modulation", "distortion"], "payload": {"question_id": "cuet-phy-comm-17", "subtopic": "modulation index limits", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "remember", "options": [{"key": "A", "text": "0.5", "is_correct": false}, {"key": "B", "text": "0.75", "is_correct": false}, {"key": "C", "text": "1", "is_correct": true}, {"key": "D", "text": "2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "m = 0.5 is within the allowed range but is not the maximum. Higher modulation up to 1 is still distortion-free.", "misconception": "Being overly conservative about the limit"}, {"option_key": "B", "hint": "m = 0.75 is used in practice for safety margin, but theoretically m = 1 is the maximum for distortion-free AM.", "misconception": "Confusing practical recommendation with theoretical limit"}, {"option_key": "D", "hint": "m = 2 means the message amplitude is twice the carrier — this causes severe over-modulation and envelope distortion.", "misconception": "Thinking modulation index can exceed 1 without distortion"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The critical frequency of an ionospheric layer with maximum electron density Nmax is given by fc = 9√(Nmax). If Nmax = 10¹² electrons/m³, the critical frequency is:", "explanation": "fc = 9√(Nmax) = 9√(10¹²) = 9 × 10⁶ Hz = 9 MHz. The critical frequency is the maximum frequency that can be reflected by the ionosphere at vertical incidence. Frequencies above fc pass through the ionosphere and cannot be used for sky wave communication.", "correct_answer": "C", "concept_tags": ["critical-frequency", "electron-density", "ionosphere"], "payload": {"question_id": "cuet-phy-comm-18", "subtopic": "critical frequency of ionosphere", "topic_name": "Propagation of EM Waves", "bloom_level": "apply", "options": [{"key": "A", "text": "9 kHz", "is_correct": false}, {"key": "B", "text": "900 kHz", "is_correct": false}, {"key": "C", "text": "9 MHz", "is_correct": true}, {"key": "D", "text": "90 MHz", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "9 kHz = 9 × 10³ Hz. Check: 9√(10¹²) = 9 × 10⁶ Hz = 9 MHz, not 9 kHz.", "misconception": "Error in calculating √(10¹²) — should be 10⁶, not 10³"}, {"option_key": "B", "hint": "900 kHz = 9 × 10⁵ Hz, which would need Nmax = 10¹⁰. For Nmax = 10¹², fc = 9 × 10⁶.", "misconception": "Off by a factor of 10"}, {"option_key": "D", "hint": "90 MHz = 9 × 10⁷ Hz would need Nmax ≈ 10¹⁴, not 10¹². Exponent error.", "misconception": "Adding instead of halving the exponent in square root"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-elements", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A repeater in a communication system is used to:", "explanation": "A repeater receives the attenuated signal, amplifies it, and retransmits it. It extends the range of communication by compensating for signal loss (attenuation) during transmission over long distances. Repeaters are placed at intervals along the communication channel.", "correct_answer": "B", "concept_tags": ["repeater", "amplification", "range-extension"], "payload": {"question_id": "cuet-phy-comm-19", "subtopic": "repeater", "topic_name": "Elements of Communication System", "bloom_level": "remember", "options": [{"key": "A", "text": "Convert analog signals to digital", "is_correct": false}, {"key": "B", "text": "Extend the range by amplifying and retransmitting the signal", "is_correct": true}, {"key": "C", "text": "Modulate the carrier wave", "is_correct": false}, {"key": "D", "text": "Reduce noise in the signal", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Analog-to-digital conversion is done by an ADC (analog-to-digital converter), not a repeater.", "misconception": "Confusing repeater with ADC"}, {"option_key": "C", "hint": "Modulation is done at the transmitter. A repeater works on an already modulated signal.", "misconception": "Confusing repeater with modulator"}, {"option_key": "D", "hint": "While digital repeaters can regenerate signals, the primary function is to amplify and retransmit, not noise reduction.", "misconception": "Confusing a secondary benefit with the primary function"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An AM wave is represented as: y = [10 + 6 sin(2π × 1500t)] sin(2π × 10⁵ t). The modulation index and carrier frequency are:", "explanation": "Comparing with the standard form y = Ac[1 + m sin(2πfmt)] sin(2πfct): Ac = 10, mAc = 6, so m = 6/10 = 0.6. The carrier frequency fc = 10⁵ Hz = 100 kHz. The modulating frequency fm = 1500 Hz = 1.5 kHz.", "correct_answer": "A", "concept_tags": ["AM-wave-equation", "extract-parameters", "carrier-frequency"], "payload": {"question_id": "cuet-phy-comm-20", "subtopic": "AM wave equation analysis", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "0.6 and 100 kHz", "is_correct": true}, {"key": "B", "text": "0.6 and 1.5 kHz", "is_correct": false}, {"key": "C", "text": "6 and 100 kHz", "is_correct": false}, {"key": "D", "text": "0.06 and 10⁵ MHz", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "1.5 kHz is the modulating frequency (fm), not the carrier frequency. The carrier is the higher frequency: 10⁵ Hz = 100 kHz.", "misconception": "Confusing modulating frequency with carrier frequency"}, {"option_key": "C", "hint": "m = Am/Ac = 6/10 = 0.6, not 6. The modulation index is a ratio, always ≤ 1 for distortion-free AM.", "misconception": "Using the amplitude directly instead of the ratio"}, {"option_key": "D", "hint": "10⁵ Hz = 100 kHz = 0.1 MHz, not 10⁵ MHz. Also m = 0.6, not 0.06.", "misconception": "Unit confusion between Hz and MHz"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The total power of an AM wave is 600 W. If the modulation index is 0.75, the power of the carrier wave is:", "explanation": "Total AM power: Pt = Pc(1 + m²/2). So Pc = Pt/(1 + m²/2) = 600/(1 + 0.75²/2) = 600/(1 + 0.5625/2) = 600/(1 + 0.28125) = 600/1.28125 ≈ 468.3 W.", "correct_answer": "B", "concept_tags": ["AM-power", "carrier-power", "numerical"], "payload": {"question_id": "cuet-phy-comm-21", "subtopic": "power calculation in AM", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "400 W", "is_correct": false}, {"key": "B", "text": "468.3 W", "is_correct": true}, {"key": "C", "text": "512 W", "is_correct": false}, {"key": "D", "text": "300 W", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "400 W corresponds to Pt/(1 + m²) instead of Pt/(1 + m²/2). The denominator has m²/2, not m².", "misconception": "Using wrong formula: forgetting the ½ factor"}, {"option_key": "C", "hint": "Check: 600/1.28125 ≈ 468.3, not 512. Recompute the denominator carefully.", "misconception": "Arithmetic error in division"}, {"option_key": "D", "hint": "300 W is half the total power, implying m²/2 = 1 i.e. m = √2. But m = 0.75.", "misconception": "Simply halving the total power"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Satellite communication uses which mode of wave propagation?", "explanation": "Satellite communication uses space wave (line-of-sight) propagation. Signals are transmitted from Earth to a satellite at frequencies above 30 MHz (typically GHz range), which pass straight through the ionosphere without reflection. The satellite receives, amplifies, and retransmits the signal back to a different location on Earth.", "correct_answer": "C", "concept_tags": ["satellite", "space-wave", "line-of-sight"], "payload": {"question_id": "cuet-phy-comm-22", "subtopic": "satellite communication", "topic_name": "Propagation of EM Waves", "bloom_level": "remember", "options": [{"key": "A", "text": "Ground wave propagation", "is_correct": false}, {"key": "B", "text": "Sky wave propagation", "is_correct": false}, {"key": "C", "text": "Space wave propagation", "is_correct": true}, {"key": "D", "text": "Surface wave propagation", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Ground wave follows Earth''s surface and works only below 2 MHz. Satellite uses GHz frequencies.", "misconception": "Confusing ground wave with space wave"}, {"option_key": "B", "hint": "Sky wave uses ionospheric reflection (2–30 MHz). Satellite frequencies are much higher and pass through the ionosphere.", "misconception": "Thinking satellite signals bounce off the ionosphere"}, {"option_key": "D", "hint": "Surface wave is another name for ground wave propagation. Not used for satellite communication.", "misconception": "Using alternate terminology for ground wave"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two towers of heights 50 m and 72 m are separated by 40 km. What is the maximum distance between them for line-of-sight communication? (R = 6.4 × 10⁶ m)", "explanation": "For two towers, maximum LOS distance = √(2Rh₁) + √(2Rh₂). d₁ = √(2 × 6.4 × 10⁶ × 50) = √(6.4 × 10⁸) = 25.3 km. d₂ = √(2 × 6.4 × 10⁶ × 72) = √(9.216 × 10⁸) = 30.36 km. Total = 25.3 + 30.36 = 55.66 km. Since 40 km < 55.66 km, they CAN communicate. The maximum distance is 55.66 km.", "correct_answer": "C", "concept_tags": ["two-tower-range", "LOS-distance", "numerical"], "payload": {"question_id": "cuet-phy-comm-23", "subtopic": "two-tower line-of-sight", "topic_name": "Propagation of EM Waves", "bloom_level": "apply", "options": [{"key": "A", "text": "25.3 km", "is_correct": false}, {"key": "B", "text": "30.4 km", "is_correct": false}, {"key": "C", "text": "55.7 km", "is_correct": true}, {"key": "D", "text": "40 km", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "25.3 km is the range of tower 1 alone (h = 50 m). For two towers, add both individual ranges.", "misconception": "Using only one tower''s range"}, {"option_key": "B", "hint": "30.4 km is the range of tower 2 alone (h = 72 m). The total LOS distance is d₁ + d₂.", "misconception": "Using only the taller tower''s range"}, {"option_key": "D", "hint": "40 km is the actual separation given, not the maximum possible LOS distance.", "misconception": "Confusing actual separation with maximum range"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-detection", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The first step in AM detection (demodulation) is:", "explanation": "AM detection involves: (1) Rectification — a diode removes one half of the AM wave (since the envelope has symmetric positive and negative halves), leaving a pulsating signal. (2) Filtering — a low-pass (RC) filter removes the carrier frequency ripple, leaving only the message signal envelope.", "correct_answer": "A", "concept_tags": ["AM-detection", "rectification", "diode"], "payload": {"question_id": "cuet-phy-comm-24", "subtopic": "AM detection steps", "topic_name": "Detection and Demodulation", "bloom_level": "understand", "options": [{"key": "A", "text": "Rectification using a diode", "is_correct": true}, {"key": "B", "text": "Amplification using a transistor", "is_correct": false}, {"key": "C", "text": "Filtering using a band-pass filter", "is_correct": false}, {"key": "D", "text": "Mixing with a local oscillator", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Amplification may be needed, but the essential first step of detection is rectification to extract the envelope.", "misconception": "Confusing amplification with detection"}, {"option_key": "C", "hint": "Band-pass filtering is used in the tuning stage (before detection) to select the desired station, not in detection itself.", "misconception": "Confusing station selection with signal detection"}, {"option_key": "D", "hint": "Mixing with a local oscillator is used in superheterodyne receivers, which is an advanced technique, not basic AM envelope detection.", "misconception": "Confusing simple detection with heterodyne detection"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-elements", "exam_ids": ["CUET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Long-distance radio communication is possible due to reflection of radio waves by the ionosphere.\nReason (R): The ionosphere contains a high density of free electrons that reflect radio waves in the frequency range 2 MHz to 30 MHz.", "explanation": "Both A and R are true, and R correctly explains A. The ionosphere''s free electrons (produced by solar UV radiation ionising atmospheric gases) cause total internal reflection of radio waves below the critical frequency. This allows short-wave radio signals (2–30 MHz) to travel thousands of kilometres by bouncing between Earth and ionosphere.", "correct_answer": "A", "concept_tags": ["ionosphere-reflection", "sky-wave", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-comm-25", "subtopic": "ionospheric propagation", "topic_name": "Elements of Communication System", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A — the free electrons cause the reflection that enables long-distance communication.", "misconception": "Not connecting electron density to wave reflection"}, {"option_key": "C", "hint": "R is correct — the ionosphere does contain free electrons (10¹⁰–10¹² per m³) that reflect radio waves.", "misconception": "Doubting the ionosphere''s electron content"}, {"option_key": "D", "hint": "A is true — shortwave radio has been used for intercontinental communication since the 1920s via ionospheric reflection.", "misconception": "Denying the well-established phenomenon of sky wave communication"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): In AM transmission, the carrier wave carries no information.\nReason (R): In amplitude modulation, information is contained in the sideband frequencies, not in the carrier frequency.", "explanation": "Both A and R are true, and R correctly explains A. The carrier is a constant-amplitude, constant-frequency wave that acts as a ''vehicle'' for the message. The actual information is encoded in the sidebands (fc ± fm) created by modulation. This is why the carrier power (which is the dominant power in AM) is essentially wasted, making AM inefficient.", "correct_answer": "A", "concept_tags": ["carrier-no-info", "sidebands-carry-info", "AM-efficiency"], "payload": {"question_id": "cuet-phy-comm-26", "subtopic": "information content in AM", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "analyse", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R is the precise explanation of A — the carrier carries no info because the sidebands carry all the information.", "misconception": "Not seeing the direct logical link"}, {"option_key": "C", "hint": "R is factually correct. In the AM spectrum, removing the carrier and keeping only sidebands still preserves all the message information.", "misconception": "Thinking the carrier contains message information"}, {"option_key": "D", "hint": "A is true — the carrier frequency fc remains constant and carries no varying information.", "misconception": "Confusing the carrier wave with the modulated wave"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Television signals cannot be received beyond a certain distance from the transmitting tower.\nReason (R): TV signals travel as space waves and are limited by the curvature of the Earth.", "explanation": "Both A and R are true, and R correctly explains A. TV signals use VHF/UHF frequencies (above 30 MHz) which propagate as space waves (line-of-sight). They are not reflected by the ionosphere and cannot follow Earth''s curvature. The range is limited to d = √(2Rh), determined by the tower height and Earth''s radius.", "correct_answer": "A", "concept_tags": ["TV-range", "space-wave-limitation", "earth-curvature"], "payload": {"question_id": "cuet-phy-comm-27", "subtopic": "TV signal range limitation", "topic_name": "Propagation of EM Waves", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R is the exact reason for A — space wave propagation and Earth''s curvature directly cause the range limitation.", "misconception": "Not connecting propagation mode to range limit"}, {"option_key": "C", "hint": "R is correct — TV signals do propagate as space waves and are limited by Earth''s curvature.", "misconception": "Thinking TV signals use sky wave propagation"}, {"option_key": "D", "hint": "A is true — without satellite relay, TV reception is limited to line-of-sight range from the tower.", "misconception": "Thinking TV signals can travel unlimited distances"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-elements", "exam_ids": ["CUET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following communication terms (Column-I) with their descriptions (Column-II):\n\nColumn-I: (P) Attenuation (Q) Noise (R) Bandwidth (S) Modulation\nColumn-II: (1) Range of frequencies occupied by a signal (2) Loss of signal strength during transmission (3) Superimposing message on a carrier wave (4) Unwanted signals that distort the message", "explanation": "P→2: Attenuation is the gradual loss of signal strength as it travels through the channel. Q→4: Noise consists of unwanted electrical signals from various sources that corrupt the message. R→1: Bandwidth is the range of frequencies a signal occupies or a channel can handle. S→3: Modulation is the process of combining the message signal with a high-frequency carrier.", "correct_answer": "A", "concept_tags": ["terminology", "matching", "communication-basics"], "payload": {"question_id": "cuet-phy-comm-28", "subtopic": "communication terminology", "topic_name": "Elements of Communication System", "bloom_level": "remember", "options": [{"key": "A", "text": "P→2, Q→4, R→1, S→3", "is_correct": true}, {"key": "B", "text": "P→4, Q→2, R→1, S→3", "is_correct": false}, {"key": "C", "text": "P→2, Q→4, R→3, S→1", "is_correct": false}, {"key": "D", "text": "P→1, Q→4, R→2, S→3", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "P→4 confuses attenuation with noise. Attenuation is signal weakening (2), noise is unwanted signals (4).", "misconception": "Swapping attenuation and noise definitions"}, {"option_key": "C", "hint": "R→3 assigns ''superimposing on carrier'' to bandwidth. Bandwidth is about frequency range (1), not modulation.", "misconception": "Confusing bandwidth with modulation"}, {"option_key": "D", "hint": "P→1 assigns ''frequency range'' to attenuation. Attenuation is about signal strength loss, not frequency.", "misconception": "Confusing attenuation with bandwidth"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following frequency ranges (Column-I) with their propagation modes (Column-II):\n\nColumn-I: (P) Below 2 MHz (Q) 2–30 MHz (R) Above 30 MHz (S) Above 3 GHz\nColumn-II: (1) Satellite communication (2) Sky wave (ionospheric) (3) Ground wave (surface) (4) Space wave (line-of-sight)", "explanation": "P→3: Below 2 MHz uses ground wave propagation along Earth''s surface (AM radio). Q→2: 2–30 MHz uses sky wave — reflected by the ionosphere (shortwave radio). R→4: Above 30 MHz uses space wave — line-of-sight propagation (TV, FM). S→1: Above 3 GHz uses satellite communication — passes through ionosphere to geostationary satellites.", "correct_answer": "B", "concept_tags": ["frequency-propagation-mapping", "matching", "modes"], "payload": {"question_id": "cuet-phy-comm-29", "subtopic": "propagation mode vs frequency", "topic_name": "Propagation of EM Waves", "bloom_level": "remember", "options": [{"key": "A", "text": "P→3, Q→4, R→2, S→1", "is_correct": false}, {"key": "B", "text": "P→3, Q→2, R→4, S→1", "is_correct": true}, {"key": "C", "text": "P→2, Q→3, R→4, S→1", "is_correct": false}, {"key": "D", "text": "P→3, Q→2, R→1, S→4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Q→4 assigns space wave to 2–30 MHz. This range actually uses sky wave (ionospheric reflection).", "misconception": "Swapping sky wave and space wave"}, {"option_key": "C", "hint": "P→2 assigns sky wave to below 2 MHz. Low frequencies use ground wave, not sky wave.", "misconception": "Swapping ground wave and sky wave"}, {"option_key": "D", "hint": "R→1 assigns satellite to above 30 MHz and S→4 assigns space wave to above 3 GHz. It''s the reverse.", "misconception": "Swapping satellite and space wave ranges"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the following parameters of AM wave (Column-I) with their expressions (Column-II):\n\nColumn-I: (P) Modulation index (Q) Bandwidth of AM (R) Power of AM wave (S) Upper sideband frequency\nColumn-II: (1) fc + fm (2) Pc(1 + m²/2) (3) Am/Ac (4) 2fm", "explanation": "P→3: Modulation index m = Am/Ac (ratio of message amplitude to carrier amplitude). Q→4: AM bandwidth = 2fm (twice the modulating frequency). R→2: Total AM power = Pc(1 + m²/2). S→1: Upper sideband frequency = fc + fm.", "correct_answer": "C", "concept_tags": ["AM-formulas", "matching", "key-expressions"], "payload": {"question_id": "cuet-phy-comm-30", "subtopic": "AM formulas", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "remember", "options": [{"key": "A", "text": "P→3, Q→1, R→2, S→4", "is_correct": false}, {"key": "B", "text": "P→4, Q→3, R→2, S→1", "is_correct": false}, {"key": "C", "text": "P→3, Q→4, R→2, S→1", "is_correct": true}, {"key": "D", "text": "P→3, Q→4, R→1, S→2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Q→1 assigns fc + fm to bandwidth. fc + fm is the upper sideband frequency, not the bandwidth.", "misconception": "Confusing sideband frequency with bandwidth"}, {"option_key": "B", "hint": "P→4 assigns 2fm to modulation index. 2fm is the bandwidth, and Am/Ac is the modulation index.", "misconception": "Swapping modulation index and bandwidth expressions"}, {"option_key": "D", "hint": "R→1 assigns fc + fm to power. AM power is Pc(1 + m²/2), not related to fc + fm.", "misconception": "Confusing power expression with frequency expression"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-elements", "exam_ids": ["CUET"], "question_type": "true-false", "difficulty": "easy", "question_text": "In a communication system, the transmitter and receiver must operate at the same frequency for successful communication.", "explanation": "This statement is TRUE. The receiver must be tuned to the same carrier frequency as the transmitter to successfully receive and demodulate the signal. If the receiver is tuned to a different frequency, it will pick up a different station or no signal at all. This is the principle behind tuning a radio to a specific station.", "correct_answer": "A", "concept_tags": ["tuning", "frequency-matching", "receiver"], "payload": {"question_id": "cuet-phy-comm-31", "subtopic": "tuning principle", "topic_name": "Elements of Communication System", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "If receiver and transmitter frequencies don''t match, the receiver''s tuning circuit won''t select the intended signal.", "misconception": "Thinking any receiver can pick up any frequency without tuning"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Frequencies above 30 MHz cannot be reflected by the ionosphere.", "explanation": "This statement is TRUE. The ionosphere can only reflect radio waves below the critical frequency (typically up to about 30 MHz, depending on electron density). Frequencies above 30 MHz penetrate through the ionosphere into space, which is why VHF TV signals and FM radio cannot use sky wave propagation and require line-of-sight towers.", "correct_answer": "A", "concept_tags": ["ionosphere-limit", "critical-frequency", "VHF"], "payload": {"question_id": "cuet-phy-comm-32", "subtopic": "ionospheric frequency limit", "topic_name": "Propagation of EM Waves", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is why TV transmitters need tall towers — their VHF/UHF signals pass through the ionosphere instead of bouncing back.", "misconception": "Thinking the ionosphere reflects all radio frequencies"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "true-false", "difficulty": "medium", "question_text": "In amplitude modulation, the frequency of the modulated wave remains the same as the carrier frequency.", "explanation": "This statement is FALSE. While the central (dominant) frequency is the carrier frequency, the modulated wave actually contains three frequencies: fc, fc + fm, and fc − fm. The AM wave is not a single frequency — it spans a bandwidth of 2fm around the carrier. However, the carrier frequency component itself remains unchanged.", "correct_answer": "B", "concept_tags": ["AM-frequencies", "sidebands", "frequency-content"], "payload": {"question_id": "cuet-phy-comm-33", "subtopic": "frequency content of AM wave", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The AM wave contains sideband frequencies (fc ± fm) in addition to the carrier. It is NOT a single-frequency wave.", "misconception": "Thinking AM only changes amplitude without adding new frequencies"}]}}]'::jsonb, 'deploy-2026-03-05-b06');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-bandwidth", "exam_ids": ["CUET"], "question_type": "true-false", "difficulty": "medium", "question_text": "A video signal requires more bandwidth than an audio signal.", "explanation": "This statement is TRUE. A video signal has a bandwidth of about 4.2 MHz (analog TV), while an audio signal requires only about 20 kHz (music) or 3 kHz (speech). Video requires vastly more bandwidth because it carries two-dimensional spatial information changing rapidly in time, while audio is a one-dimensional signal.", "correct_answer": "A", "concept_tags": ["video-bandwidth", "audio-bandwidth", "comparison"], "payload": {"question_id": "cuet-phy-comm-34", "subtopic": "bandwidth comparison", "topic_name": "Bandwidth of Signals and Channels", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Video bandwidth (~4.2 MHz) is about 200× more than music bandwidth (~20 kHz). More information requires more bandwidth.", "misconception": "Thinking audio and video need similar bandwidths"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-detection", "exam_ids": ["CUET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "The device used for selecting a desired station in a radio receiver is called a ______.", "explanation": "A band-pass filter (or tuning circuit, typically an LC circuit) is used to select a specific radio station. It allows only a narrow band of frequencies (around the desired station''s carrier frequency) to pass through while rejecting all other stations. Tuning the radio changes the resonant frequency of this LC circuit.", "correct_answer": "A", "concept_tags": ["band-pass-filter", "tuning", "station-selection"], "payload": {"question_id": "cuet-phy-comm-35", "subtopic": "receiver tuning", "topic_name": "Detection and Demodulation", "bloom_level": "remember", "options": [{"key": "A", "text": "Band-pass filter (tuning circuit)", "is_correct": true}, {"key": "B", "text": "Low-pass filter", "is_correct": false}, {"key": "C", "text": "Rectifier", "is_correct": false}, {"key": "D", "text": "Demodulator", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A low-pass filter passes all frequencies below a cutoff. For station selection, you need to select a narrow band — that''s a band-pass filter.", "misconception": "Confusing low-pass with band-pass filtering"}, {"option_key": "C", "hint": "A rectifier (diode) is used in the detection stage after station selection, not for selecting the station.", "misconception": "Confusing detection with tuning"}, {"option_key": "D", "hint": "A demodulator extracts the message from the carrier. It operates after the desired station has been selected.", "misconception": "Confusing demodulation with station selection"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The modulation index m of an AM wave whose maximum and minimum amplitudes are 10 V and 4 V respectively is ______.", "explanation": "m = (Amax − Amin)/(Amax + Amin) = (10 − 4)/(10 + 4) = 6/14 = 3/7 ≈ 0.43. This formula is derived from Amax = Ac(1+m) and Amin = Ac(1−m). Subtracting: Amax − Amin = 2mAc. Adding: Amax + Amin = 2Ac. Dividing: m = (Amax − Amin)/(Amax + Amin).", "correct_answer": "B", "concept_tags": ["modulation-index-formula", "Amax-Amin-method", "numerical"], "payload": {"question_id": "cuet-phy-comm-36", "subtopic": "modulation index from amplitudes", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "0.6", "is_correct": false}, {"key": "B", "text": "3/7 ≈ 0.43", "is_correct": true}, {"key": "C", "text": "0.4", "is_correct": false}, {"key": "D", "text": "2.5", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.6 = 6/10, which would use m = (Amax − Amin)/Amax. The correct formula divides by (Amax + Amin).", "misconception": "Using wrong denominator in the formula"}, {"option_key": "C", "hint": "0.4 = 4/10 = Amin/Amax, which is not the modulation index formula.", "misconception": "Using ratio of min to max instead of the correct formula"}, {"option_key": "D", "hint": "2.5 = 10/4 = Amax/Amin. The modulation index must be ≤ 1 for distortion-free AM.", "misconception": "Using the amplitude ratio instead of the modulation formula"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-elements", "exam_ids": ["CUET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "The loss of signal strength as it propagates through the communication channel is called ______.", "explanation": "Attenuation is the gradual decrease in signal amplitude (strength) as the signal travels through the channel. It occurs due to spreading of energy, absorption by the medium, and scattering. Attenuation is measured in decibels (dB) and is a major reason why repeaters and amplifiers are needed in long-distance communication.", "correct_answer": "C", "concept_tags": ["attenuation", "signal-loss", "channel"], "payload": {"question_id": "cuet-phy-comm-37", "subtopic": "signal attenuation", "topic_name": "Elements of Communication System", "bloom_level": "remember", "options": [{"key": "A", "text": "Noise", "is_correct": false}, {"key": "B", "text": "Distortion", "is_correct": false}, {"key": "C", "text": "Attenuation", "is_correct": true}, {"key": "D", "text": "Interference", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Noise is unwanted signal added to the original — it doesn''t reduce the signal, it corrupts it.", "misconception": "Confusing signal corruption with signal weakening"}, {"option_key": "B", "hint": "Distortion changes the shape/waveform of the signal, not its overall strength.", "misconception": "Confusing waveform change with amplitude loss"}, {"option_key": "D", "hint": "Interference is when multiple signals combine and disrupt each other. Attenuation is loss of a single signal''s strength.", "misconception": "Confusing multi-signal interaction with single-signal weakening"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A radio station broadcasts at a carrier frequency of 1200 kHz. The station uses amplitude modulation with audio signals ranging from 100 Hz to 5 kHz.\n\nThe range of frequencies occupied by the AM broadcast is:", "explanation": "The AM signal extends from fc − fm(max) to fc + fm(max). Here fc = 1200 kHz and fm(max) = 5 kHz. Lower limit = 1200 − 5 = 1195 kHz. Upper limit = 1200 + 5 = 1205 kHz. The AM broadcast occupies 1195 kHz to 1205 kHz, a bandwidth of 10 kHz.", "correct_answer": "A", "concept_tags": ["AM-spectrum-range", "sideband-extent", "scenario"], "payload": {"question_id": "cuet-phy-comm-38", "subtopic": "frequency occupation of AM", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "1195 kHz to 1205 kHz", "is_correct": true}, {"key": "B", "text": "1199.9 kHz to 1205 kHz", "is_correct": false}, {"key": "C", "text": "100 Hz to 1205 kHz", "is_correct": false}, {"key": "D", "text": "1195 kHz to 1200 kHz", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "1199.9 kHz uses the minimum audio frequency (100 Hz = 0.1 kHz). The full extent uses the maximum: 5 kHz from the carrier.", "misconception": "Using minimum modulating frequency for the sideband extent"}, {"option_key": "C", "hint": "The original audio frequencies (100 Hz to 5 kHz) are NOT present in the AM signal. Only the shifted sidebands around fc exist.", "misconception": "Including baseband frequencies in the AM spectrum"}, {"option_key": "D", "hint": "This shows only the lower sideband. AM produces both upper and lower sidebands symmetrically around fc.", "misconception": "Forgetting the upper sideband"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-propagation", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A transmitting antenna at the top of a tower has a height of 45 m and the receiving antenna has a height of 80 m. Calculate the maximum line-of-sight distance between them. (R = 6400 km)", "explanation": "Maximum LOS distance = √(2Rh₁) + √(2Rh₂). d₁ = √(2 × 6.4 × 10⁶ × 45) = √(5.76 × 10⁸) = 2.4 × 10⁴ m = 24 km. d₂ = √(2 × 6.4 × 10⁶ × 80) = √(10.24 × 10⁸) = 3.2 × 10⁴ m = 32 km. Total = 24 + 32 = 56 km.", "correct_answer": "C", "concept_tags": ["two-antenna-LOS", "numerical", "range-formula"], "payload": {"question_id": "cuet-phy-comm-39", "subtopic": "two-antenna range calculation", "topic_name": "Propagation of EM Waves", "bloom_level": "apply", "options": [{"key": "A", "text": "24 km", "is_correct": false}, {"key": "B", "text": "32 km", "is_correct": false}, {"key": "C", "text": "56 km", "is_correct": true}, {"key": "D", "text": "112 km", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "24 km is only the range of the transmitting antenna (h = 45 m). You must add the receiving antenna''s range too.", "misconception": "Calculating range of only one antenna"}, {"option_key": "B", "hint": "32 km is only the range of the receiving antenna (h = 80 m). Total LOS = d₁ + d₂.", "misconception": "Calculating range of only the taller antenna"}, {"option_key": "D", "hint": "112 km = 2 × 56 km. There is no factor of 2 in the two-antenna formula: dmax = d₁ + d₂.", "misconception": "Doubling the correct answer erroneously"}]}}, {"chapter_id": "cuet-phy-communication", "topic_id": "cuet-phy-comm-modulation", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A carrier wave of peak voltage 12 V is used to transmit a message signal. The modulated signal has a maximum voltage of 18 V and a minimum voltage of 6 V.\n\nThe percentage modulation and the peak voltage of the modulating signal are:", "explanation": "Carrier amplitude Ac = 12 V. Amax = 18 V = Ac + Am, so Am = 18 − 12 = 6 V. Verification: Amin = Ac − Am = 12 − 6 = 6 V ✓. Modulation index m = Am/Ac = 6/12 = 0.5. Percentage modulation = 50%. Alternatively: m = (Amax − Amin)/(Amax + Amin) = (18 − 6)/(18 + 6) = 12/24 = 0.5.", "correct_answer": "B", "concept_tags": ["percentage-modulation", "peak-voltage", "AM-calculation"], "payload": {"question_id": "cuet-phy-comm-40", "subtopic": "modulation index and signal amplitude", "topic_name": "Modulation and Amplitude Modulation", "bloom_level": "apply", "options": [{"key": "A", "text": "75% and 9 V", "is_correct": false}, {"key": "B", "text": "50% and 6 V", "is_correct": true}, {"key": "C", "text": "50% and 12 V", "is_correct": false}, {"key": "D", "text": "33% and 4 V", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "75% means m = 0.75, which gives Amax = 12(1+0.75) = 21 V, not 18 V.", "misconception": "Incorrectly calculating modulation index"}, {"option_key": "C", "hint": "Peak voltage of modulating signal Am = 6 V, not 12 V. 12 V is the carrier amplitude Ac.", "misconception": "Confusing message amplitude with carrier amplitude"}, {"option_key": "D", "hint": "33% gives m = 0.33, so Amax = 12(1.33) = 16 V, not 18 V. Check: m = (18−6)/(18+6) = 0.5.", "misconception": "Using wrong formula or arithmetic error"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following is NOT an electromagnetic wave?", "explanation": "Ultrasound waves are mechanical (longitudinal) waves that require a material medium for propagation. They are pressure variations in air, water, or tissue. All the other options — X-rays, microwaves, and gamma rays — are electromagnetic waves that can travel through vacuum.", "correct_answer": "C", "concept_tags": ["em-wave-types", "mechanical-vs-em", "ultrasound"], "payload": {"question_id": "cuet-phy-emwave-21", "subtopic": "nature of electromagnetic waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "X-rays", "is_correct": false}, {"key": "B", "text": "Microwaves", "is_correct": false}, {"key": "C", "text": "Ultrasound waves", "is_correct": true}, {"key": "D", "text": "Gamma rays", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "X-rays are high-frequency electromagnetic waves used in medical imaging. They travel through vacuum.", "misconception": "Thinking X-rays need a medium"}, {"option_key": "B", "hint": "Microwaves are EM waves with wavelengths in the cm range, used in ovens and communication.", "misconception": "Confusing microwaves with sound waves"}, {"option_key": "D", "hint": "Gamma rays are the highest-frequency electromagnetic waves, emitted by radioactive nuclei.", "misconception": "Confusing nuclear radiation with mechanical waves"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Electromagnetic waves travel in vacuum with a speed of:", "explanation": "All electromagnetic waves travel in vacuum at the speed of light, c = 3 × 10⁸ m/s, regardless of their frequency or wavelength. This is a fundamental constant of nature derived from Maxwell''s equations: c = 1/√(μ₀ε₀).", "correct_answer": "B", "concept_tags": ["speed-of-light", "vacuum", "maxwell-equations"], "payload": {"question_id": "cuet-phy-emwave-22", "subtopic": "speed of electromagnetic waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "3 × 10⁶ m/s", "is_correct": false}, {"key": "B", "text": "3 × 10⁸ m/s", "is_correct": false}, {"key": "C", "text": "3 × 10¹⁰ m/s", "is_correct": false}, {"key": "D", "text": "Speed depends on wavelength", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3 × 10⁶ m/s is 1000 times slower than light. This is roughly 1% of the speed of light.", "misconception": "Confusing order of magnitude"}, {"option_key": "C", "hint": "3 × 10¹⁰ m/s would exceed the speed of light, violating special relativity.", "misconception": "Exaggerating the speed of EM waves"}, {"option_key": "D", "hint": "In vacuum, all EM waves travel at the same speed c, regardless of wavelength. Speed depends on wavelength only in a dispersive medium.", "misconception": "Applying medium-dispersion properties to vacuum"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which electromagnetic waves are used in RADAR systems?", "explanation": "RADAR (Radio Detection And Ranging) uses microwaves, typically in the frequency range of 1–300 GHz. Microwaves are ideal because they can penetrate clouds, are reflected well by metallic objects, and can be focused into narrow beams using dish antennas.", "correct_answer": "C", "concept_tags": ["radar", "microwaves", "applications"], "payload": {"question_id": "cuet-phy-emwave-23", "subtopic": "applications of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Infrared waves", "is_correct": false}, {"key": "B", "text": "Ultraviolet rays", "is_correct": false}, {"key": "C", "text": "Microwaves", "is_correct": true}, {"key": "D", "text": "Gamma rays", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Infrared waves are used in remote controls, night vision, and thermal imaging — not in RADAR.", "misconception": "Confusing IR applications with RADAR"}, {"option_key": "B", "hint": "UV rays are absorbed by the atmosphere and are used in sterilisation, not for detection and ranging.", "misconception": "Mixing up UV applications"}, {"option_key": "D", "hint": "Gamma rays are extremely high-energy and penetrating — impractical and dangerous for detection systems.", "misconception": "Thinking higher energy means better detection"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The wavelength range of visible light is approximately:", "explanation": "Visible light spans roughly 400 nm (violet) to 700 nm (red). This narrow band of the electromagnetic spectrum is the only portion detectable by the human eye. Below 400 nm lies ultraviolet, and above 700 nm lies infrared.", "correct_answer": "B", "concept_tags": ["visible-light", "wavelength-range", "spectrum"], "payload": {"question_id": "cuet-phy-emwave-24", "subtopic": "electromagnetic spectrum", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "1 nm to 400 nm", "is_correct": false}, {"key": "B", "text": "400 nm to 700 nm", "is_correct": true}, {"key": "C", "text": "700 nm to 1 mm", "is_correct": false}, {"key": "D", "text": "1 mm to 1 m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1–400 nm covers ultraviolet and X-ray ranges, which are invisible to the human eye.", "misconception": "Confusing UV range with visible light"}, {"option_key": "C", "hint": "700 nm to 1 mm is the infrared region, felt as heat but not seen by the eye.", "misconception": "Extending visible range into infrared"}, {"option_key": "D", "hint": "1 mm to 1 m is the microwave range, used in communication and cooking.", "misconception": "Confusing microwave with visible wavelengths"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the electric field component of an EM wave is E₀ sin(kz − ωt)x̂, the magnetic field component is:", "explanation": "In an electromagnetic wave, E and B are perpendicular to each other and to the direction of propagation. If E is along x̂ and propagation is along ẑ, then B must be along ŷ. The amplitude relation is B₀ = E₀/c. Both fields have the same phase, so B = (E₀/c) sin(kz − ωt)ŷ.", "correct_answer": "A", "concept_tags": ["E-B-relation", "wave-propagation", "amplitude-ratio"], "payload": {"question_id": "cuet-phy-emwave-25", "subtopic": "relation between E and B", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "(E₀/c) sin(kz − ωt)ŷ", "is_correct": true}, {"key": "B", "text": "E₀c sin(kz − ωt)ŷ", "is_correct": false}, {"key": "C", "text": "(E₀/c) sin(kz − ωt)ẑ", "is_correct": false}, {"key": "D", "text": "(E₀/c) cos(kz − ωt)ŷ", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "B₀ = E₀/c, not E₀c. Since c ≈ 3×10⁸, E₀c would give an enormously large magnetic field.", "misconception": "Inverting the E-B amplitude relation"}, {"option_key": "C", "hint": "ẑ is the direction of propagation. B cannot oscillate along the direction of wave travel — EM waves are transverse.", "misconception": "Placing B along the propagation direction"}, {"option_key": "D", "hint": "E and B are in phase in an EM wave. If E has sin(kz − ωt), B also has sin(kz − ωt), not cos.", "misconception": "Thinking E and B have a 90° phase difference"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ozone layer in the Earth''s atmosphere absorbs mainly:", "explanation": "The ozone (O₃) layer in the stratosphere strongly absorbs ultraviolet (UV) radiation from the Sun, particularly UV-B (280–315 nm) and UV-C (100–280 nm). This absorption protects living organisms from harmful UV radiation that can cause skin cancer and DNA damage.", "correct_answer": "B", "concept_tags": ["ozone-layer", "uv-absorption", "atmosphere"], "payload": {"question_id": "cuet-phy-emwave-26", "subtopic": "applications and effects of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Infrared radiation", "is_correct": false}, {"key": "B", "text": "Ultraviolet radiation", "is_correct": true}, {"key": "C", "text": "Visible light", "is_correct": false}, {"key": "D", "text": "Radio waves", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Infrared is mainly absorbed by water vapour and CO₂ (greenhouse gases), not ozone.", "misconception": "Confusing ozone absorption with greenhouse effect"}, {"option_key": "C", "hint": "Visible light passes through the atmosphere largely unabsorbed — that''s why we can see the Sun.", "misconception": "Thinking ozone blocks visible light"}, {"option_key": "D", "hint": "Radio waves pass through the atmosphere and are not absorbed by ozone. The ionosphere reflects some radio waves.", "misconception": "Confusing ozone layer with ionosphere"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The displacement current through a parallel plate capacitor of capacitance C is related to the voltage V across it by:", "explanation": "Displacement current Id = ε₀(dΦE/dt). For a parallel plate capacitor, ΦE = Q/(ε₀) and Q = CV, so Id = dQ/dt = C(dV/dt). This equals the conduction current flowing in the external circuit, maintaining continuity of current through the capacitor gap.", "correct_answer": "C", "concept_tags": ["displacement-current", "capacitor", "maxwell"], "payload": {"question_id": "cuet-phy-emwave-27", "subtopic": "displacement current", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "Id = V/C", "is_correct": false}, {"key": "B", "text": "Id = CV", "is_correct": false}, {"key": "C", "text": "Id = C(dV/dt)", "is_correct": true}, {"key": "D", "text": "Id = V(dC/dt)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "V/C has units of V/F = Coulombs, not Amperes. Current must involve a time derivative.", "misconception": "Confusing charge with current"}, {"option_key": "B", "hint": "CV gives charge Q, not current. You need the rate of change of charge for current.", "misconception": "Forgetting that current is dQ/dt, not Q"}, {"option_key": "D", "hint": "Capacitance C is fixed for a given capacitor geometry; dC/dt = 0 under normal conditions.", "misconception": "Thinking capacitance varies with time"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following EM waves has the longest wavelength?", "explanation": "In the electromagnetic spectrum, radio waves have the longest wavelength (ranging from ~1 mm to thousands of kilometres). The order from longest to shortest wavelength is: radio > microwave > infrared > visible > UV > X-ray > gamma ray.", "correct_answer": "D", "concept_tags": ["spectrum-order", "wavelength-comparison", "radio-waves"], "payload": {"question_id": "cuet-phy-emwave-28", "subtopic": "electromagnetic spectrum ordering", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "X-rays", "is_correct": false}, {"key": "B", "text": "Infrared rays", "is_correct": false}, {"key": "C", "text": "Microwaves", "is_correct": false}, {"key": "D", "text": "Radio waves", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "X-rays have very short wavelengths (0.01–10 nm), among the shortest in the EM spectrum.", "misconception": "Confusing penetrating power with wavelength"}, {"option_key": "B", "hint": "Infrared has wavelengths from ~700 nm to 1 mm — longer than visible but shorter than microwaves and radio.", "misconception": "Thinking IR is the longest wavelength"}, {"option_key": "C", "hint": "Microwaves (1 mm to ~30 cm) are longer than IR but shorter than radio waves.", "misconception": "Confusing microwave and radio wave ranges"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An EM wave has a frequency of 5 × 10¹⁴ Hz. Its wavelength is:", "explanation": "Using c = fλ, we get λ = c/f = (3 × 10⁸)/(5 × 10¹⁴) = 6 × 10⁻⁷ m = 600 nm. This falls in the visible light range (orange-yellow region), confirming the answer is reasonable.", "correct_answer": "B", "concept_tags": ["wavelength-frequency", "c-equals-f-lambda", "numerical"], "payload": {"question_id": "cuet-phy-emwave-29", "subtopic": "wave equation c = fλ", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "6 × 10⁻⁵ m", "is_correct": false}, {"key": "B", "text": "6 × 10⁻⁷ m", "is_correct": true}, {"key": "C", "text": "6 × 10⁻⁹ m", "is_correct": false}, {"key": "D", "text": "6 × 10⁻³ m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "6 × 10⁻⁵ m = 60 μm, which lies in the far infrared — too long for a frequency of 10¹⁴ Hz.", "misconception": "Error in power of ten calculation"}, {"option_key": "C", "hint": "6 × 10⁻⁹ m = 6 nm, which is in the X-ray range — way too short for visible frequency.", "misconception": "Subtracting exponents incorrectly: 8−14 ≠ −9"}, {"option_key": "D", "hint": "6 × 10⁻³ m = 6 mm lies in the microwave range. This would correspond to a much lower frequency (~50 GHz).", "misconception": "Major arithmetic error in exponents"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The intensity of an electromagnetic wave is proportional to:", "explanation": "The intensity (power per unit area) of an EM wave is I = ½ε₀cE₀², so it is proportional to the square of the amplitude of the electric field. Equivalently, I = B₀²c/(2μ₀). Intensity is proportional to E₀², not E₀ or E₀³.", "correct_answer": "B", "concept_tags": ["intensity", "electric-field-amplitude", "energy"], "payload": {"question_id": "cuet-phy-emwave-30", "subtopic": "intensity of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "E₀", "is_correct": false}, {"key": "B", "text": "E₀²", "is_correct": true}, {"key": "C", "text": "E₀³", "is_correct": false}, {"key": "D", "text": "1/E₀²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Intensity involves energy, which depends on the square of the field amplitude — just like kinetic energy depends on v².", "misconception": "Forgetting the squared dependence of energy on amplitude"}, {"option_key": "C", "hint": "No standard wave formula involves the cube of amplitude. Energy density is always proportional to amplitude².", "misconception": "Randomly guessing the power dependence"}, {"option_key": "D", "hint": "Intensity increases with stronger electric field. An inverse-square relation would mean weaker fields give more energy.", "misconception": "Inverting the relationship"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A plane electromagnetic wave of frequency 25 MHz travels in free space along the x-direction. At a particular point and time, E = 6.3 V/m ŷ. The magnetic field B at that point and time is:", "explanation": "B₀ = E₀/c = 6.3/(3 × 10⁸) = 2.1 × 10⁻⁸ T. Since E is along ŷ and wave propagates along x̂, B must be along ẑ (using E × B ∝ direction of propagation: ŷ × ẑ = x̂). So B = 2.1 × 10⁻⁸ T ẑ.", "correct_answer": "A", "concept_tags": ["E-B-numerical", "direction", "cross-product"], "payload": {"question_id": "cuet-phy-emwave-31", "subtopic": "E and B field calculation", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "2.1 × 10⁻⁸ T ẑ", "is_correct": true}, {"key": "B", "text": "2.1 × 10⁻⁸ T x̂", "is_correct": false}, {"key": "C", "text": "1.89 × 10⁹ T ẑ", "is_correct": false}, {"key": "D", "text": "2.1 × 10⁻⁸ T (−ẑ)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "x̂ is the direction of propagation. B cannot point along the wave''s travel direction — EM waves are transverse.", "misconception": "Placing B along propagation direction"}, {"option_key": "C", "hint": "This value uses B = Ec instead of B = E/c. The magnetic field amplitude is always much smaller than E in SI units.", "misconception": "Using B = Ec instead of B = E/c"}, {"option_key": "D", "hint": "For E along +ŷ and propagation along +x̂, E × B must give +x̂. ŷ × ẑ = x̂ (correct), but ŷ × (−ẑ) = −x̂ (wrong direction).", "misconception": "Getting the cross-product sign wrong"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An EM wave of wavelength λ is incident on a slit of width d. Diffraction effects are significant when:", "explanation": "Diffraction becomes significant when the wavelength is comparable to or larger than the obstacle/slit size, i.e., λ ≥ d (or d ≈ λ). When d >> λ, the wave passes through with negligible diffraction (ray optics limit). When d << λ, the wave bends around the slit almost completely.", "correct_answer": "C", "concept_tags": ["diffraction-condition", "wavelength-slit", "wave-nature"], "payload": {"question_id": "cuet-phy-emwave-32", "subtopic": "wave properties of EM radiation", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "d >> λ", "is_correct": false}, {"key": "B", "text": "d << λ", "is_correct": false}, {"key": "C", "text": "d ≈ λ", "is_correct": true}, {"key": "D", "text": "λ = 0", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "When d >> λ, the slit is much wider than the wavelength — light goes straight through with minimal bending (geometric optics).", "misconception": "Thinking large slit causes more diffraction"}, {"option_key": "B", "hint": "When d << λ, diffraction is extreme (wave bends around completely), but the question asks when effects become ''significant'' — the onset is at d ≈ λ.", "misconception": "Partially correct but not the threshold condition"}, {"option_key": "D", "hint": "λ = 0 would mean infinite frequency — no real wave has zero wavelength.", "misconception": "Not understanding the physical meaning"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The average energy density in an electromagnetic wave with electric field amplitude E₀ is:", "explanation": "The average energy density of an EM wave is u = ½ε₀E₀². This can also be written as u = B₀²/(2μ₀). The electric and magnetic field contributions are equal: uE = ¼ε₀E₀² and uB = ¼ε₀E₀², giving total u = ½ε₀E₀².", "correct_answer": "B", "concept_tags": ["energy-density", "electric-field", "average"], "payload": {"question_id": "cuet-phy-emwave-33", "subtopic": "energy in EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "ε₀E₀²", "is_correct": false}, {"key": "B", "text": "½ε₀E₀²", "is_correct": true}, {"key": "C", "text": "¼ε₀E₀²", "is_correct": false}, {"key": "D", "text": "2ε₀E₀²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "ε₀E₀² is the peak energy density of the electric field alone. The average (over one cycle) introduces a factor of ½.", "misconception": "Forgetting to take the time average of sin²"}, {"option_key": "C", "hint": "¼ε₀E₀² is the average energy density of only the electric field part. You must add the equal magnetic field contribution.", "misconception": "Forgetting the magnetic field contribution"}, {"option_key": "D", "hint": "2ε₀E₀² is four times the correct answer. There''s no physical basis for this factor.", "misconception": "Doubling both peak and average incorrectly"}]}}]'::jsonb, 'deploy-2026-03-05-b06');

COMMIT;
